INSERT INTO mame_games (rank, id, title, consoleName, consoleId, totalPlayers, casualPlayers, hardcorePlayers, numAchievements, points, genre, developer, publisher, released, description, icon, boxArt, titleScreen, screenshot, rating) VALUES
  (1, 11750, 'Metal Slug: Super Vehicle-001', 'Arcade', 27, 13017, 13017, 13017, 32, 0, 'Run & Gun', 'Nazca', 'SNK', '1996-04-01', 'Metal Slug is a 1996 run and gun video game developed by Nazca Corporation and originally released by SNK for the Neo Geo MVS arcade system. Set in 2028, the game follows Peregrine Falcon Strike Force soldiers Marco Rossi and Tarma Roving as they seek to overthrow a coup d''état by the Rebel Army, led by Donald Morden.', 'https://media.retroachievements.org/Images/049652.png', 'https://media.retroachievements.org/Images/016022.png', 'https://media.retroachievements.org/Images/016020.png', 'https://media.retroachievements.org/Images/016021.png', 5),
  (2, 11763, 'Cadillacs and Dinosaurs', 'Arcade', 27, 8353, 8353, 8353, 44, 0, NULL, 'Capcom', 'Capcom', '1993-04-01', 'Cadillacs and Dinosaurs, released in Japan as Cadillacs Kyouryuu Shinseiki , is a 1993 side-scrolling beat ''em up arcade game by Capcom, based on the comic book series Xenozoic Tales. The game was produced as a tie-in to the short-lived Cadillacs and Dinosaurs animated series which was aired during the same year the game was released. A version for the Capcom Power System Changer was planned and previewed but never released.', 'https://media.retroachievements.org/Images/101998.png', 'https://media.retroachievements.org/Images/016000.png', 'https://media.retroachievements.org/Images/016008.png', 'https://media.retroachievements.org/Images/016006.png', 4.9),
  (3, 11795, 'Street Fighter III: 3rd Strike - Fight for the Future', 'Arcade', 27, 6307, 6307, 6307, 46, 0, '2D Fighting', 'Capcom', 'Capcom', '1999-05-01', 'Street Fighter III: 3rd Strike - Fight for the Future is a 1999 fighting game developed and published by Capcom for arcades. It is the second and final updated version of Street Fighter III, following Street Fighter III: 2nd Impact. Like its predecessors, it runs on the CP System III hardware.', 'https://media.retroachievements.org/Images/065554.png', 'https://media.retroachievements.org/Images/016038.png', 'https://media.retroachievements.org/Images/016036.png', 'https://media.retroachievements.org/Images/016037.png', 4.8),
  (4, 11770, 'Metal Slug X: Super Vehicle-001', 'Arcade', 27, 6129, 6129, 6129, 37, 0, 'Run & Gun', 'SNK', 'SNK', '1999-03-01', 'Metal Slug 2 is a run and gun arcade game developed by SNK. It was originally released in 1998 for the Neo-Geo MVS arcade platform as the sequel to the 1996 game Metal Slug. The original version of the game had extensive slowdown and performance issues, eventually leading SNK to release a modified version in 1999, titled Metal Slug X: Super Vehicle-001 (メタルスラッグX). It has been ported to the Neo Geo CD, PlayStation, Virtual Console, iOS and Android, and to the Wii, PlayStation Portable and PlayStation 2. The game added several new features to the gameplay of the original Metal Slug, such as new weapons, vehicles and the ability to transform the character. It received generally positive reviews and was followed by Metal Slug 3, released in 2000.', 'https://media.retroachievements.org/Images/049658.png', 'https://media.retroachievements.org/Images/015990.png', 'https://media.retroachievements.org/Images/015937.png', 'https://media.retroachievements.org/Images/015938.png', 4.8),
  (5, 11727, 'Final Fight', 'Arcade', 27, 5945, 5945, 5945, 49, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1989-12-01', 'Final Fight is a series of beat ''em up video games by Japanese publisher Capcom, which began with the arcade release of Final Fight in 1989. Set in the fictional Metro City, within the Street Fighter universe, the games focus on a group of heroic vigilantes who fight against the control and various threats of criminal gangs, primarily the Mad Gear Gang. The series has sold 3.2 million units worldwide as of June 30, 2023.', 'https://media.retroachievements.org/Images/106799.png', 'https://media.retroachievements.org/Images/016661.png', 'https://media.retroachievements.org/Images/016659.png', 'https://media.retroachievements.org/Images/062589.png', 4.8),
  (6, 11825, 'Metal Slug 2: Super Vehicle-001/II', 'Arcade', 27, 5786, 5786, 5786, 36, 0, 'Run & Gun', 'SNK', 'SNK', '1998-02-01', 'Metal Slug 2 is a run and gun arcade game developed by SNK. It was originally released in 1998 for the Neo-Geo MVS arcade platform as the sequel to the 1996 game Metal Slug. The original version of the game had extensive slowdown and performance issues, eventually leading SNK to release a modified version in 1999, titled Metal Slug X: Super Vehicle-001 (メタルスラッグX). It has been ported to the Neo Geo CD, PlayStation, Virtual Console, iOS and Android, and to the Wii, PlayStation Portable and PlayStation 2. The game added several new features to the gameplay of the original Metal Slug, such as new weapons, vehicles and the ability to transform the character. It received generally positive reviews and was followed by Metal Slug 3, released in 2000.', 'https://media.retroachievements.org/Images/086571.png', 'https://media.retroachievements.org/Images/016064.png', 'https://media.retroachievements.org/Images/016062.png', 'https://media.retroachievements.org/Images/016063.png', 4.7),
  (7, 11726, 'Captain Commando', 'Arcade', 27, 4501, 4501, 4501, 54, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1991-11-01', 'Captain Commando is a 1991 beat ''em up game developed and published by Capcom for arcades. It was the seventeenth game produced for the company''s CP System hardware. The game stars the titular superhero, who was originally conceived as a fictional spokesman used by Capcom USA in the company''s console games during the late 1980s. The game was included in Capcom Beat ''Em Up Bundle compilation title, which was released digitally for Nintendo Switch, PlayStation 4, Xbox One, and Windows in September 2018.', 'https://media.retroachievements.org/Images/028296.png', 'https://media.retroachievements.org/Images/028254.png', 'https://media.retroachievements.org/Images/028256.png', 'https://media.retroachievements.org/Images/028257.png', 4.7),
  (8, 11787, 'The Punisher', 'Arcade', 27, 4387, 4387, 4387, 50, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1993-01-01', 'The Punisher is an antihero appearing in American comic books published by Marvel Comics. The character was created by writer Gerry Conway and artists John Romita Sr. and Ross Andru.', 'https://media.retroachievements.org/Images/016671.png', 'https://media.retroachievements.org/Images/016637.png', 'https://media.retroachievements.org/Images/016669.png', 'https://media.retroachievements.org/Images/016670.png', 4.7),
  (9, 11820, 'Alien vs. Predator', 'Arcade', 27, 4130, 4130, 4130, 48, 0, NULL, 'Capcom', 'Capcom', '1994-05-20', 'Alien vs. Predator is a science fiction action horror media franchise created by comic book writers Randy Stradley and Chris Warner. The series is a crossover between, and part of, the larger Alien and Predator franchises, depicting the two species — Xenomorph (Alien) and Yautja (Predator) — as being in conflict with one another.', 'https://media.retroachievements.org/Images/018851.png', 'https://media.retroachievements.org/Images/018884.png', 'https://media.retroachievements.org/Images/018883.png', 'https://media.retroachievements.org/Images/018882.png', 4.6),
  (10, 11943, 'Donkey Kong', 'Arcade', 27, 4063, 4063, 4063, 18, 0, '2D Platforming, Arcade', NULL, 'Nintendo', '1981-07-09', 'Donkey Kong is a video game series and media franchise created by the Japanese game designer Shigeru Miyamoto for Nintendo. It follows the adventures of Donkey Kong, a large, powerful gorilla, and other members of the Kong family of apes. Donkey Kong games include the original arcade game trilogy by Nintendo R&D1; the Donkey Kong Country series by Rare and Retro Studios; and the Mario vs. Donkey Kong series by Nintendo Software Technology. Various studios have developed spin-offs in genres such as edutainment, puzzle, racing, and rhythm. The franchise also incorporates animation, printed media, theme parks, and merchandise.', 'https://media.retroachievements.org/Images/122436.png', 'https://media.retroachievements.org/Images/036163.png', 'https://media.retroachievements.org/Images/036164.png', 'https://media.retroachievements.org/Images/036165.png', 4.6),
  (11, 11771, 'Metal Slug 3', 'Arcade', 27, 3763, 3763, 3763, 71, 0, 'Run & Gun', 'SNK', 'SNK', '2000-05-01', 'Metal Slug 3 is a run and gun video game developed by SNK. It was originally released in 2000 for the Neo-Geo MVS arcade platform as the sequel to Metal Slug 2/Metal Slug X. The music of the game was developed by Noise Factory.', 'https://media.retroachievements.org/Images/049654.png', 'https://media.retroachievements.org/Images/021974.png', 'https://media.retroachievements.org/Images/016013.png', 'https://media.retroachievements.org/Images/016012.png', 4.6),
  (12, 11757, 'The King of Fighters ''98: The Slugfest', 'Arcade', 27, 3633, 3633, 3633, 97, 0, '2D Fighting', 'SNK', 'SNK', '1998-07-01', 'The King of Fighters ''98 , subtitled Dream Match Never Ends in Japan or The Slugfest elsewhere, is a 1998 fighting game developed and published by SNK for the Neo Geo systems. It is the fifth game in The King of Fighters series and was advertised by SNK as a special edition of the series, as it features most of the characters who appeared in the previous games from KOF ''94 to ''97. The game provides no storyline in contrast to the previous games and instead is labelled as a dream match like its subtitle, where the player selects a team composed of three characters to participate in The King of Fighters tournament until reaching the boss Rugal Bernstein, even though the character dies in The King of Fighters ''95. Two fighting styles can be selected to fight and several characters have alternate versions to select with their classic moves from previous games.', 'https://media.retroachievements.org/Images/120961.png', 'https://media.retroachievements.org/Images/016426.png', 'https://media.retroachievements.org/Images/016411.png', 'https://media.retroachievements.org/Images/032666.png', 4.6),
  (13, 12026, 'Metal Slug 4', 'Arcade', 27, 3578, 3578, 3578, 65, 0, 'Run & Gun', 'Mega Enterprise', 'SNK', '2002-03-01', 'Metal Slug 4 is a run and gun arcade game for the Neo-Geo console/arcade platform, developed by Mega Enterprise along with Noise Factory and Playmore. It was released in 2002 for the Neo-Geo MVS arcade platform, and is the fourth game in the Metal Slug series. Two years later, Playmore published Metal Slug 4 for consoles.', 'https://media.retroachievements.org/Images/049656.png', 'https://media.retroachievements.org/Images/029460.png', 'https://media.retroachievements.org/Images/022089.png', 'https://media.retroachievements.org/Images/022090.png', 4.6),
  (14, 12192, 'Pac-Man', 'Arcade', 27, 3413, 3413, 3413, 21, 0, 'Maze Chase', 'Namco', 'Namco, Midway', '1980-05-22', 'Pac-Man, originally titled Puck Man in Japan, is a 1980 maze video game developed and published by Namco for arcades. It was released in Japan on May 22, 1980 and by Midway Manufacturing in North America in August 1980. The player controls Pac-Man, who must eat all the dots inside an enclosed maze while avoiding four colored ghosts. Eating large flashing dots called Power Pellets causes the ghosts to temporarily turn blue and vulnerable, allowing Pac-Man to eat the ghosts for bonus points.', 'https://media.retroachievements.org/Images/039726.png', 'https://media.retroachievements.org/Images/038818.png', 'https://media.retroachievements.org/Images/038815.png', 'https://media.retroachievements.org/Images/038816.png', 4.6),
  (15, 11975, 'Altered Beast', 'Arcade', 27, 3312, 3312, 3312, 25, 0, NULL, 'Sega', 'Sega', '1988-08-01', 'Altered Beast is a 1988 beat ''em up video game developed by Team Shinobi and published by Sega for arcades. Set in Ancient Greece, the game follows a Roman centurion who is resurrected by the Olympian god Zeus to rescue his daughter Athena from Neff, the demonic ruler of the underworld. By collecting three power-ups in a level, the player character can transform into one of five mythical beasts.', 'https://media.retroachievements.org/Images/040187.png', 'https://media.retroachievements.org/Images/027298.png', 'https://media.retroachievements.org/Images/027296.png', 'https://media.retroachievements.org/Images/027297.png', 4.6),
  (16, 11903, 'Ghouls ''n Ghosts', 'Arcade', 27, 3194, 3194, 3194, 55, 0, NULL, 'Capcom', 'Capcom', '1988-12-01', 'Ghouls ''n Ghosts, known as Dai Makaimura in Japan, is a 1988 platform game developed and published by Capcom for arcades. It is the sequel to 1985''s Ghosts ''n Goblins, and the second game in the Ghosts ''n Goblins series.', 'https://media.retroachievements.org/Images/119127.png', 'https://media.retroachievements.org/Images/032351.png', 'https://media.retroachievements.org/Images/032354.png', 'https://media.retroachievements.org/Images/032353.png', 4.6),
  (17, 14976, 'Mortal Kombat', 'Arcade', 27, 3026, 3026, 3026, 35, 0, '2D Fighting', 'Midway', 'Midway', '1992-10-08', 'Mortal Kombat is an American media franchise centered on a series of fighting video games originally developed by Midway Games in 1992.', 'https://media.retroachievements.org/Images/036812.png', 'https://media.retroachievements.org/Images/030937.png', 'https://media.retroachievements.org/Images/029345.png', 'https://media.retroachievements.org/Images/029346.png', 4.5),
  (18, 12211, 'Teenage Mutant Ninja Turtles: Turtles in Time', 'Arcade', 27, 2960, 2960, 2960, 31, 0, 'Beat ''em Up', 'Konami', 'Konami', '1991-03-01', 'Teenage Mutant Ninja Turtles (TMNT) is an American media franchise created by comic book artists Kevin Eastman and Peter Laird. It follows Leonardo, Donatello, Raphael and Michelangelo, four anthropomorphic turtle brothers trained in ninjutsu who fight evil in New York City. The franchise encompasses printed media, television series, feature films, video games, and merchandise.', 'https://media.retroachievements.org/Images/101616.png', 'https://media.retroachievements.org/Images/028706.png', 'https://media.retroachievements.org/Images/075426.png', 'https://media.retroachievements.org/Images/075427.png', 4.5),
  (19, 12154, 'Golden Axe', 'Arcade', 27, 2936, 2936, 2936, 32, 0, 'Beat ''em Up', 'Sega', 'Sega', '1989-01-01', 'Golden Axe  is a series of side-scrolling beat ''em up arcade video games developed by Sega. The series takes place in a medieval fantasy world where several heroes have the task of recovering the legendary Golden Axe, the mainstay element of the series.', 'https://media.retroachievements.org/Images/036853.png', 'https://media.retroachievements.org/Images/032938.png', 'https://media.retroachievements.org/Images/030228.png', 'https://media.retroachievements.org/Images/030232.png', 4.5),
  (20, 12210, 'Teenage Mutant Ninja Turtles', 'Arcade', 27, 2902, 2902, 2902, 29, 0, 'Beat ''em Up', 'Konami', 'Konami', '1989-11-15', 'Teenage Mutant Ninja Turtles (TMNT) is an American media franchise created by comic book artists Kevin Eastman and Peter Laird. It follows Leonardo, Donatello, Raphael and Michelangelo, four anthropomorphic turtle brothers trained in ninjutsu who fight evil in New York City. The franchise encompasses printed media, television series, feature films, video games, and merchandise.', 'https://media.retroachievements.org/Images/101615.png', 'https://media.retroachievements.org/Images/028202.png', 'https://media.retroachievements.org/Images/033249.png', 'https://media.retroachievements.org/Images/033227.png', 4.5),
  (21, 11806, 'Marvel vs. Capcom: Clash of Super Heroes', 'Arcade', 27, 2893, 2893, 2893, 92, 0, '2D Fighting', 'Capcom', 'Capcom', '1998-01-01', 'Marvel vs. Capcom: Clash of Super Heroes is a 1998 crossover fighting game developed and published by Capcom for the CP System II arcade system. It is the third installment in the Marvel vs. Capcom series, which features characters from Capcom''s video game franchises and characters from Marvel Comics. Unlike the series'' previous entry, Marvel Super Heroes vs. Street Fighter (1997), this sequel features characters from numerous Capcom video game franchises, rather than strictly Street Fighter characters. While the gameplay is largely identical to its predecessor, Clash of Super Heroes removes the traditional character assist system and introduces the Variable Cross attack.', 'https://media.retroachievements.org/Images/106812.png', 'https://media.retroachievements.org/Images/036230.png', 'https://media.retroachievements.org/Images/016016.png', 'https://media.retroachievements.org/Images/016017.png', 4.5),
  (22, 13796, 'Neo Turf Masters', 'Arcade', 27, 2875, 2875, 2875, 25, 0, 'Sports - Golf', 'Nazca', 'Nazca', '1996-01-01', 'Neo Turf Masters is a golf video game by Nazca for the Neo Geo, released in 1996. This is also one of the first two titles by Nazca before being acquired by SNK; the other series being the popular Metal Slug.', 'https://media.retroachievements.org/Images/029954.png', 'https://media.retroachievements.org/Images/029955.png', 'https://media.retroachievements.org/Images/022152.png', 'https://media.retroachievements.org/Images/022153.png', 4.5),
  (23, 11971, 'Aliens', 'Arcade', 27, 2844, 2844, 2844, 38, 0, NULL, 'Konami', 'Konami', '1990-03-01', 'Alien vs. Predator (エイリアンVSプレデター) is a 1994 beat ''em up video game developed and released by Capcom for the CPS-2 arcade game system. It is based on the science fiction franchise of the same name. Introducing an original fighter to the game: Lt. Kurosawa, the players take control of up to three from the selection of four cyborgs and Predator characters in a battle against the Xenomorph hordes and rogue human soldiers.', 'https://media.retroachievements.org/Images/059994.png', 'https://media.retroachievements.org/Images/019654.png', 'https://media.retroachievements.org/Images/019652.png', 'https://media.retroachievements.org/Images/019653.png', 4.5),
  (24, 12323, 'Neo Drift Out: New Technology', 'Arcade', 27, 2841, 2841, 2841, 25, 0, 'Arcade Racing', 'Visco', 'Visco', '1996-03-01', 'Neo Drift Out: New Technology is a 1996 rallying video game developed by Visco Corporation for the Neo Geo and Neo Geo CD. It is the fourth title in the Drift Out series. Though it follows Super Drift Out: World Rally Championships, it is closer to the earlier Drift Out ''94: The Hard Order.', 'https://media.retroachievements.org/Images/033493.png', 'https://media.retroachievements.org/Images/033494.png', 'https://media.retroachievements.org/Images/020918.png', 'https://media.retroachievements.org/Images/022149.png', 4.5),
  (25, 11800, 'Ms. Pac-Man', 'Arcade', 27, 2657, 2657, 2657, 27, 0, 'Maze Chase', 'General Computer Corporation, Midway', 'Midway', '1982-01-13', 'Ms. Pac-Man is a 1982 maze video game developed by General Computer Corporation (GCC) and published by Midway Manufacturing for arcades. It is a sequel to Pac-Man (1980), and the first entry in the series to not be made by Namco. Controlling the title character, Pac-Man''s wife, the player is tasked with eating all of the pellets in an enclosed maze while avoiding four colored ghosts. Eating the larger power pellets lets the player eat the ghosts, which turn blue and flee.', 'https://media.retroachievements.org/Images/058762.png', 'https://media.retroachievements.org/Images/051061.png', 'https://media.retroachievements.org/Images/051063.png', 'https://media.retroachievements.org/Images/051062.png', 4.5),
  (26, 11960, '1942', 'Arcade', 27, 2598, 2598, 2598, 27, 0, 'Shoot ''em Up', 'Capcom', 'Capcom', '1984-12-01', '1942 (MCMXLII) was a common year starting on Thursday of the Gregorian calendar, the 1942nd year of the Common Era (CE) and Anno Domini (AD) designations, the 942nd year of the 2nd millennium, the 42nd year of the 20th century, and the 3rd year of the 1940s decade.', 'https://media.retroachievements.org/Images/087811.png', 'https://media.retroachievements.org/Images/025220.png', 'https://media.retroachievements.org/Images/025244.png', 'https://media.retroachievements.org/Images/025245.png', 4.5),
  (27, 12027, 'Metal Slug 5', 'Arcade', 27, 2559, 2559, 2559, 39, 0, 'Run & Gun', 'SNK', 'SNK', '2003-11-01', 'Metal Slug 5 is a run and gun arcade game for the Neo-Geo, created by SNK Playmore. It was released in 2003 for the MVS arcade platform and is the fifth game in the Metal Slug series. The game was developed by Noise Factory/SNK Playmore, after Korean company Mega Enterprise had directed Metal Slug 4. It was the last Metal Slug released on the Neo Geo.', 'https://media.retroachievements.org/Images/049657.png', 'https://media.retroachievements.org/Images/016361.png', 'https://media.retroachievements.org/Images/016359.png', 'https://media.retroachievements.org/Images/016360.png', 4.5),
  (28, 12247, 'Puzzle Bobble (Neo Geo)', 'Arcade', 27, 2524, 2524, 2524, 14, 0, NULL, 'Taito', 'Taito', '1994-12-01', 'Puzzle Bobble, formerly known internationally as Bust-A-Move, is a 1994 tile-matching video game developed and published by Taito for arcades. It is based on the 1986 arcade game Bubble Bobble, featuring characters and themes from that game. Its characteristically cute Japanese animation and music, along with its play mechanics and level designs, made it successful as an arcade title and spawned several sequels and ports to home systems.', 'https://media.retroachievements.org/Images/077439.png', 'https://media.retroachievements.org/Images/016681.png', 'https://media.retroachievements.org/Images/016679.png', 'https://media.retroachievements.org/Images/016680.png', 4.5),
  (29, 11984, 'Astérix', 'Arcade', 27, 2504, 2504, 2504, 61, 0, 'Beat ''em Up', 'Konami', 'Konami', '1992-01-01', 'Asterix is a French comic album series about a Gaulish village which, thanks to a magic potion that enhances strength, resists the forces of Julius Caesar''s Roman Republic Army in the time after the Gallic Wars. Many adventures take the titular hero Asterix and his friend Obelix to Rome and beyond.', 'https://media.retroachievements.org/Images/111496.png', 'https://media.retroachievements.org/Images/026011.png', 'https://media.retroachievements.org/Images/026013.png', 'https://media.retroachievements.org/Images/026012.png', 4.5),
  (30, 11933, 'X-Men', 'Arcade', 27, 2469, 2469, 2469, 31, 0, 'Beat ''em Up', 'Konami', 'Konami', '1992-01-31', 'The X-Men are a superhero team in American comic books published by Marvel Comics. Created by writer/editor Stan Lee and artist/co-plotter Jack Kirby, the team first appeared in The X-Men #1. Although initially cancelled in 1970 due to low sales, following its 1975 revival and subsequent direction under writer Chris Claremont, it became one of Marvel Comics''s most recognizable and successful franchises. They have appeared in numerous books, television shows, 20th Century Fox''s X-Men films, and video games. The X-Men title may refer to the superhero team itself, the eponymous comic series, or the broader franchise, which includes various solo titles and team books, such as the New Mutants, Excalibur, and X-Force.', 'https://media.retroachievements.org/Images/018913.png', 'https://media.retroachievements.org/Images/018912.png', 'https://media.retroachievements.org/Images/018910.png', 'https://media.retroachievements.org/Images/018911.png', 4.5),
  (31, 12035, 'The King of Fighters 2002', 'Arcade', 27, 2415, 2415, 2415, 134, 0, '2D Fighting', 'Eolith, SNK', 'Eolith, SNK', '2002-10-01', 'The King of Fighters 2002: Challenge to Ultimate Battle (KOF 2002, or KOF ''02) is a 2002 arcade fighting video game developed by Eolith and published by Playmore, the spiritual successor to the original SNK, for the Neo Geo. It is the ninth title in The King of Fighters series and the second one to be produced by Eolith. Similarly to The King of Fighters ''98, it brings together characters from various SNK franchises and has a diverse roster of fighters.', 'https://media.retroachievements.org/Images/109236.png', 'https://media.retroachievements.org/Images/016475.png', 'https://media.retroachievements.org/Images/016464.png', 'https://media.retroachievements.org/Images/016484.png', 4.5),
  (32, 13767, 'Cyber-Lip', 'Arcade', 27, 2392, 2392, 2392, 48, 0, NULL, 'SNK', 'SNK', '1990-11-01', 'Cyber-Lip is a run and gun video game released in arcades by SNK in 1990 for the Neo Geo MVS. It was released for the Neo Geo AES home console in 1991.', 'https://media.retroachievements.org/Images/062607.png', 'https://media.retroachievements.org/Images/029870.png', 'https://media.retroachievements.org/Images/021975.png', 'https://media.retroachievements.org/Images/021976.png', 4.5),
  (33, 11991, 'Bad Dudes vs. DragonNinja', 'Arcade', 27, 2362, 2362, 2362, 55, 0, 'Beat ''em Up', 'Data East', 'Data East', '1988-01-01', 'Shinobi vs. Dragon Ninja is a song by the Welsh rock band Lostprophets. The song was released in 2001 as the first single from the band''s debut studio album, The Fake Sound of Progress. It was the only charting single on the Billboard charts from the album, and was still on the band''s tour setlist until they broke up in 2013.', 'https://media.retroachievements.org/Images/052574.png', 'https://media.retroachievements.org/Images/036839.png', 'https://media.retroachievements.org/Images/036836.png', 'https://media.retroachievements.org/Images/036837.png', 4.5),
  (34, 16525, 'Metal Slug 6', 'Arcade', 27, 2307, 2307, 2307, 35, 0, 'Run & Gun', 'Noise Factory', 'Sega, SNK', '2006-02-24', 'Metal Slug 6 is a run and gun video game for the Sammy Atomiswave arcade platform in the Metal Slug series. It was released in 2006.', 'https://media.retroachievements.org/Images/065561.png', 'https://media.retroachievements.org/Images/044150.png', 'https://media.retroachievements.org/Images/049506.png', 'https://media.retroachievements.org/Images/044149.png', 4.5),
  (35, 12138, 'Galaga', 'Arcade', 27, 2222, 2222, 2222, 17, 0, 'Shoot ''em Up', 'Namco', 'Midway', '1981-01-01', 'Galaga is a 1981 fixed shooter video game developed and published by Namco for Japanese and European arcades; it was distributed by Midway Manufacturing in North America. It is the sequel to 1979''s Galaxian, and the second game in the Galaxian series. Controlling a starship, the player is tasked with destroying the Galaga forces in each stage while avoiding enemies and projectiles. Some enemies can capture a player''s ship via a tractor beam, which can be rescued by another ship to give the player a dual fighter with additional firepower.', 'https://media.retroachievements.org/Images/096926.png', 'https://media.retroachievements.org/Images/033523.png', 'https://media.retroachievements.org/Images/033525.png', 'https://media.retroachievements.org/Images/033526.png', 4.5),
  (36, 12814, 'DonPachi', 'Arcade', 27, 2163, 2163, 2163, 47, 0, 'Shoot ''em Up, Bullet Hell', NULL, 'Atlus', '1995-11-01', 'DoDonPachi is a 1997 vertically scrolling bullet hell video game developed by Cave and published by Atlus. It was the second game developed by Cave, and the sixth on Cave''s first-generation arcade hardware. As with its predecessor DonPachi, the title is both a Japanese term for expressing the sound of gunfire, and a term that relates to bees.', 'https://media.retroachievements.org/Images/107000.png', 'https://media.retroachievements.org/Images/031380.png', 'https://media.retroachievements.org/Images/031378.png', 'https://media.retroachievements.org/Images/031379.png', 4.4),
  (37, 11932, 'Sunset Riders', 'Arcade', 27, 2054, 2054, 2054, 20, 0, NULL, 'Konami', 'Konami', '1991-09-01', 'Sunset Riders is a 1991 run and gun video game developed and published by Konami for arcades. It was released in North America in October 1991 and Japan in November 1991. It is set in the American Old West, where the player(s) take control of bounty hunters who are seeking the rewards offered for various criminals.', 'https://media.retroachievements.org/Images/123568.png', 'https://media.retroachievements.org/Images/035473.png', 'https://media.retroachievements.org/Images/035474.png', 'https://media.retroachievements.org/Images/035475.png', 4.4),
  (38, 11905, 'Nightmare in the Dark', 'Arcade', 27, 2025, 2025, 2025, 43, 0, '2D Platforming', 'AM Factory', 'Gavaking, Eleven', '2000-01-01', 'Nightmare in the Dark is a platform arcade game developed by AM Factory, with the assistance of Paon, and released by Eleven/Gavaking on January 27, 2000. The game never received an official release for either the Neo Geo AES (home) or Neo Geo CD platforms. It concerns the story of a grave keeper discovering graves being desecrated and his attempt to prevent the graverobbers from inflicting further damage.', 'https://media.retroachievements.org/Images/033374.png', 'https://media.retroachievements.org/Images/018674.png', 'https://media.retroachievements.org/Images/018673.png', 'https://media.retroachievements.org/Images/018675.png', 4.4),
  (39, 11758, 'Art of Fighting', 'Arcade', 27, 2004, 2004, 2004, 27, 0, '2D Fighting', 'SNK', 'SNK', '1992-09-24', 'Art of Fighting, known in Japan as Dragon & Tiger Fist, is a series of fighting video games created by Japanese game designer Hiroshi Matsumoto. Originally released for the Neo Geo platform in the early 1990s, it is the second fighting game franchise created by SNK, following the Fatal Fury series, and is set in the same fictional universe. The original Art of Fighting was released in 1992, followed by two sequels: Art of Fighting 2 in 1994 and Art of Fighting 3: The Path of the Warrior in 1996. A new Art of Fighting game is currently in development. The trilogy primarily focus on two martial artists known as Ryo Sakazaki and Robert Garcia as they use their Kyokugenryu Karate to face enemies in their quests explored in the trilogy of games. Such skills are obtained across bonus from the first game while they become integrated in the two sequels with new characters becoming playable.', 'https://media.retroachievements.org/Images/106171.png', 'https://media.retroachievements.org/Images/016606.png', 'https://media.retroachievements.org/Images/016604.png', 'https://media.retroachievements.org/Images/016605.png', 4.4),
  (40, 11935, 'OutRun', 'Arcade', 27, 1994, 1994, 1994, 18, 0, 'Arcade Racing', 'Sega', 'Sega', '1986-09-20', 'Out Run is 1986 racing video game developed and published by Sega for arcades. It is known for its pioneering hardware and graphics, nonlinear gameplay, a selectable soundtrack with music composed by Hiroshi Kawaguchi, and the hydraulic motion simulator deluxe arcade cabinet. The goal is to avoid traffic and reach one of five destinations before time runs out.', 'https://media.retroachievements.org/Images/051079.png', 'https://media.retroachievements.org/Images/051084.png', 'https://media.retroachievements.org/Images/051082.png', 'https://media.retroachievements.org/Images/051083.png', 4.4),
  (41, 11954, '1941: Counter Attack', 'Arcade', 27, 1979, 1979, 1979, 28, 0, 'Shoot ''em Up', 'Capcom', 'Capcom', '1990-02-01', '1941: Counter Attack is a 1990 vertically scrolling shooter video game developed and published by Capcom for arcades. It is the prequel to 1942, and the third game in the 194X series. It was ported to the SuperGrafx in 1991 and to GameTap. It was released on Capcom Classics Collection Remixed for the PlayStation Portable and Capcom Classics Collection Vol. 2 for PlayStation 2 and Xbox. It was followed by 19XX: The War Against Destiny in 1996.', 'https://media.retroachievements.org/Images/095176.png', 'https://media.retroachievements.org/Images/025224.png', 'https://media.retroachievements.org/Images/025252.png', 'https://media.retroachievements.org/Images/025253.png', 4.4),
  (42, 13762, 'Burning Fight', 'Arcade', 27, 1963, 1963, 1963, 34, 0, 'Beat ''em Up', 'SNK', 'SNK', '1991-04-01', 'Burning Fight is a 1991 beat ''em up video game developed and published by SNK for arcades on the Neo Geo MVS system. Introduced to capture a share in the then-popular beat ''em ups market, it was meant to compete with Technōs'' Double Dragon, the leader of the genre at the time. Three years after its release in the arcades and on the Neo Geo AES, it was released on Neo Geo CD as the only other home version.', 'https://media.retroachievements.org/Images/032965.png', 'https://media.retroachievements.org/Images/032933.png', 'https://media.retroachievements.org/Images/021951.png', 'https://media.retroachievements.org/Images/021952.png', 4.4),
  (43, 12543, 'League Bowling', 'Arcade', 27, 1941, 1941, 1941, 25, 0, 'Sports - Bowling', 'SNK', 'SNK', '1990-12-10', 'League Bowling is a sports arcade game released in 1990 by SNK for the Neo Geo console and arcade systems. The players controls characters with red and blue hair and can select balls from 8 to 15 pounds. It is the only bowling game released on the Neo Geo.', 'https://media.retroachievements.org/Images/052902.png', 'https://media.retroachievements.org/Images/030279.png', 'https://media.retroachievements.org/Images/022070.png', 'https://media.retroachievements.org/Images/022071.png', 4.4),
  (44, 12031, 'The King of Fighters ''97', 'Arcade', 27, 1932, 1932, 1932, 112, 0, '2D Fighting', 'SNK', 'SNK', '1997-07-01', 'The King of Fighters ''97, often shortened as KOF ''97, is a 1997 fighting video game developed and published by SNK for its Neo Geo multi-video system (MVS) arcade platform and its Advanced Entertainment System (AES) home console. It is the fourth game in The King of Fighters (KOF) series. The game was ported to the Neo Geo CD console and released worldwide; it was also ported to the PlayStation and Sega Saturn consoles in Japan. KOF ''97 is the last game in the Orochi Saga storyline, which began in The King of Fighters ''95. The new tournament focuses on the servants of the demon Yamata no Orochi, also known as the Will of Gaia, who plan to revive their master by gathering energy and sacrifices from the fighters in the KOF tournament. KOF ''97 introduced many new playable characters to the series, including five brand new characters, two existing characters from SNK''s Fatal Fury series, as well as several alternate versions of new and existing characters, such as Orochi Yashiro and Orochi Leona.', 'https://media.retroachievements.org/Images/109345.png', 'https://media.retroachievements.org/Images/016425.png', 'https://media.retroachievements.org/Images/016409.png', 'https://media.retroachievements.org/Images/016416.png', 4.4),
  (45, 12248, 'Puzzle Bobble 2 (Neo Geo)', 'Arcade', 27, 1927, 1927, 1927, 60, 0, NULL, 'Taito', 'Taito', '1999-09-01', 'Puzzle Bobble 2 is a tile-matching video game by Taito. The first sequel to Puzzle Bobble, it is also known in Europe and North America as Bust-A-Move Again for arcades and Bust-A-Move 2: Arcade Edition for home consoles. Released into the arcades in 1995, home conversions followed for the PlayStation, Sega Saturn, Nintendo 64, and Windows platforms. The game was included in Taito Legends 2, but the US arcade version was included in the US PS2 version instead. Further ports for the Nintendo Switch, PlayStation 4, and Xbox One were released by City Connection alongside Puzzle Bobble 3 in February 2023.', 'https://media.retroachievements.org/Images/032927.png', 'https://media.retroachievements.org/Images/022233.png', 'https://media.retroachievements.org/Images/022234.png', 'https://media.retroachievements.org/Images/022235.png', 4.4),
  (46, 12274, 'Street Fighter III: New Generation', 'Arcade', 27, 1906, 1906, 1906, 88, 0, '2D Fighting', 'Capcom', 'Capcom', '1997-02-01', 'Street Fighter III: New Generation  is a 1997 fighting game in Capcom''s Street Fighter series, originally released as a coin-operated arcade game. The sequel to Street Fighter II (1991), it initially discarded every previous character except for Ryu and Ken, introducing an all-new roster led by Alex. Likewise, a new antagonist named Gill took over M. Bison''s role from the previous games as the new boss character.', 'https://media.retroachievements.org/Images/065723.png', 'https://media.retroachievements.org/Images/047573.png', 'https://media.retroachievements.org/Images/031292.png', 'https://media.retroachievements.org/Images/031293.png', 4.4),
  (47, 11895, 'Wild West C.O.W.-Boys of Moo Mesa', 'Arcade', 27, 1877, 1877, 1877, 42, 0, NULL, 'Konami', 'Konami', '1992-11-01', 'Wild West C.O.W.-Boys of Moo Mesa is a 1992 American animated television series created by comic book artist Ryan Brown, known for his work on Teenage Mutant Ninja Turtles. It aired as part of ABC''s Saturday morning lineup.', 'https://media.retroachievements.org/Images/032973.png', 'https://media.retroachievements.org/Images/032976.png', 'https://media.retroachievements.org/Images/032977.png', 'https://media.retroachievements.org/Images/032978.png', 4.4),
  (48, 12266, 'Marvel Super Heroes vs. Street Fighter', 'Arcade', 27, 1845, 1845, 1845, 70, 0, '2D Fighting', 'Capcom', 'Capcom', '1997-06-25', 'Marvel Super Heroes  is a 1995 fighting game developed and published by Capcom. Originally released for arcades on the CPS-2 arcade system, it was ported to the Sega Saturn and PlayStation in 1997. The game, alongside Marvel vs. Capcom: Clash of Super Heroes, was also included in the Marvel vs. Capcom Origins compilation, released digitally for the PlayStation 3 and Xbox 360 in 2012.', 'https://media.retroachievements.org/Images/106811.png', 'https://media.retroachievements.org/Images/016285.png', 'https://media.retroachievements.org/Images/016283.png', 'https://media.retroachievements.org/Images/016284.png', 4.4),
  (49, 12394, 'Contra', 'Arcade', 27, 1810, 1810, 1810, 22, 0, 'Run & Gun', 'Konami', 'Konami', '1987-01-01', 'Contra is a 1987 run and gun game developed and published by Konami for arcades. A home version was released for the Nintendo Entertainment System in 1988, along with ports for various home computer formats, including the MSX2. The arcade and computer versions were localized as Gryzor in Europe, and the NES version as Probotector in the PAL region.', 'https://media.retroachievements.org/Images/108513.png', 'https://media.retroachievements.org/Images/059065.png', 'https://media.retroachievements.org/Images/058205.png', 'https://media.retroachievements.org/Images/058204.png', 4.4),
  (50, 12241, 'Magician Lord', 'Arcade', 27, 1787, 1787, 1787, 59, 0, '2D Platforming, Action', 'ADK', 'ADK', '1990-04-26', 'Magician Lord is a 1990 action-platform video game developed by Alpha Denshi and published by SNK for arcades on the Neo Geo MVS system. It was one of the launch titles for the MVS, as well as its home counterpart, the Neo Geo AES, which launched in 1991. The player controls Elta, a magician who embarks on a journey to recover the stolen magic tomes from the evil sorcerer Gal and his followers before Az Atorse, the god of destruction, is revived and destroys the land of Cadacis and the world.', 'https://media.retroachievements.org/Images/052904.png', 'https://media.retroachievements.org/Images/115486.png', 'https://media.retroachievements.org/Images/022076.png', 'https://media.retroachievements.org/Images/022077.png', 4.4),
  (51, 11752, 'Garou: Mark of the Wolves', 'Arcade', 27, 1780, 1780, 1780, 96, 0, '2D Fighting', 'SNK', 'SNK', '1999-11-11', 'Garou: Mark of the Wolves is a 1999 fighting game developed and published by SNK, originally for the Neo Geo and then as Fatal Fury: Mark of the Wolves for the Dreamcast. It is the sixth main installment in the Fatal Fury series. Though released a year after Real Bout Fatal Fury 2: The Newcomers (1998), the game is canonically a sequel to Real Bout Fatal Fury (1995), taking place a decade after the events of that game. Ten years after combatant Terry Bogard kills crimelord Geese Howard in The King of Fighters tournament, he and his adoptive son, Rock Howard, enter into a South Town tournament known as Maximum Mayhem to learn about the Howard legacy. The game features 14 characters, all new, with the exception of Terry Bogard. As a fighting game, the game employs two innovative mechanics, the first known as T.O.P, which provides players with powerful attacks when their health is within a certain range, and the second known as Just Defend, which provides players with various advantages if they block attacks at precise moments.', 'https://media.retroachievements.org/Images/114442.png', 'https://media.retroachievements.org/Images/017122.png', 'https://media.retroachievements.org/Images/016454.png', 'https://media.retroachievements.org/Images/016455.png', 4.4),
  (52, 12111, 'Elevator Action Returns', 'Arcade', 27, 1774, 1774, 1774, 24, 0, NULL, 'Taito', NULL, '1995-02-01', 'Elevator Action is a 1983 shooter platform video game developed and published by Taito for arcades. The player assumes the role of a secret agent infiltrating a 30-story building from the roof, then descending to ground level via elevators and stairways. Enemy agents emerge from closed doors and shoot at the player. The goal is to collect secret documents from specially marked rooms, then exit to a waiting getaway car. It runs on the Taito SJ System arcade system.', 'https://media.retroachievements.org/Images/066015.png', 'https://media.retroachievements.org/Images/063728.png', 'https://media.retroachievements.org/Images/019264.png', 'https://media.retroachievements.org/Images/019265.png', 4.4),
  (53, 11822, 'Marvel Super Heroes', 'Arcade', 27, 1766, 1766, 1766, 43, 0, '2D Fighting', 'Capcom', 'Capcom', '1995-01-01', 'Marvel Super Heroes  is a 1995 fighting game developed and published by Capcom. Originally released for arcades on the CPS-2 arcade system, it was ported to the Sega Saturn and PlayStation in 1997. The game, alongside Marvel vs. Capcom: Clash of Super Heroes, was also included in the Marvel vs. Capcom Origins compilation, released digitally for the PlayStation 3 and Xbox 360 in 2012.', 'https://media.retroachievements.org/Images/106809.png', 'https://media.retroachievements.org/Images/016033.png', 'https://media.retroachievements.org/Images/016031.png', 'https://media.retroachievements.org/Images/016032.png', 4.4),
  (54, 12271, 'Super Street Fighter II: The New Challengers', 'Arcade', 27, 1756, 1756, 1756, 45, 0, '2D Fighting', 'Capcom', 'Capcom', '1993-09-10', 'Super Street Fighter II: The New Challengers is a 1993 fighting game developed and published by Capcom for arcades. It is the fourth game in the Street Fighter II sub-series of Street Fighter games, following Street Fighter II Turbo (1992). It refines and balances the existing character roster from the previous versions, and introduces four new characters, including Fei Long, Cammy, T. Hawk, and Dee Jay. It is the first game on Capcom''s CP System II hardware, with more sophisticated graphics and audio over the original CP System hardware used in previous versions of Street Fighter II.', 'https://media.retroachievements.org/Images/120548.png', 'https://media.retroachievements.org/Images/029164.png', 'https://media.retroachievements.org/Images/095496.png', 'https://media.retroachievements.org/Images/095497.png', 4.4),
  (55, 11996, 'Buster Bros.', 'Arcade', 27, 1716, 1716, 1716, 113, 0, 'Action', 'Mitchell', 'Mitchell, Capcom', '1989-11-29', 'Buster Bros. Collection is a video game developed by Mitchell Corporation and published by Capcom for the PlayStation.', 'https://media.retroachievements.org/Images/069898.png', 'https://media.retroachievements.org/Images/070050.png', 'https://media.retroachievements.org/Images/069891.png', 'https://media.retroachievements.org/Images/070049.png', 4.4),
  (56, 13770, 'Eight Man', 'Arcade', 27, 1680, 1680, 1680, 30, 0, 'Beat ''em Up', 'Pallas', 'SNK', '1991-09-01', '8 Man , Eightman (エイトマン), or 8th Man is a manga and superhero anime created in 1963 by science fiction writer Kazumasa Hirai and manga artist Jiro Kuwata. 8 Man is considered Japan''s earliest cyborg superhero, predating Kamen Rider.', 'https://media.retroachievements.org/Images/038444.png', 'https://media.retroachievements.org/Images/038442.png', 'https://media.retroachievements.org/Images/021987.png', 'https://media.retroachievements.org/Images/021988.png', 4.4),
  (57, 11983, 'Armored Warriors', 'Arcade', 27, 1630, 1630, 1630, 26, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1994-10-24', 'Armored Warriors, known in Japan as Powered Gear: Strategic Variant Armor Equipment, is a 1994 beat ''em up video game developed and published by Capcom for arcades.', 'https://media.retroachievements.org/Images/065295.png', 'https://media.retroachievements.org/Images/065017.png', 'https://media.retroachievements.org/Images/037069.png', 'https://media.retroachievements.org/Images/037070.png', 4.4),
  (58, 12084, 'Dungeons & Dragons: Tower of Doom', 'Arcade', 27, 1629, 1629, 1629, 30, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1994-01-01', 'Dungeons & Dragons: Tower of Doom, published in 1994, is the first of two arcade games created by Capcom based on the Dungeons & Dragons tabletop role-playing game and set in the Mystara campaign setting. It is a side scrolling beat ''em up with role-playing video game elements for one to four players. The game was also released on the Sega Saturn, packaged with its sequel, Dungeons & Dragons: Shadow over Mystara, under the title Dungeons & Dragons Collection, although the Saturn version limited the gameplay to only two players. In 2013, both games were re-released for PlayStation 3, Windows, Xbox 360 and Wii U as Dungeons & Dragons: Chronicles of Mystara.', 'https://media.retroachievements.org/Images/122042.png', 'https://media.retroachievements.org/Images/025283.png', 'https://media.retroachievements.org/Images/025284.png', 'https://media.retroachievements.org/Images/025285.png', 4.4),
  (59, 12601, 'Ghost Pilots', 'Arcade', 27, 1608, 1608, 1608, 32, 0, 'Shoot ''em Up', 'SNK', 'SNK', '1991-01-25', 'Ghost Pilots is a vertically scrolling shooter arcade video game released in 1991 by SNK. It has elements similar to Capcom''s 194X series, but the player controls a seaplane.', 'https://media.retroachievements.org/Images/088117.png', 'https://media.retroachievements.org/Images/088118.png', 'https://media.retroachievements.org/Images/022038.png', 'https://media.retroachievements.org/Images/101091.png', 4.4),
  (60, 11767, 'Shock Troopers', 'Arcade', 27, 1559, 1559, 1559, 55, 0, NULL, 'Saurus', 'SNK', '1997-11-01', 'Shock Troopers is a run and gun arcade game developed by Saurus and published by SNK in 1997 for the Neo-Geo arcade MVS platform. Gameplay involves taking command of one or three soldiers in an eight-way shooter. A second game in the series, Shock Troopers: 2nd Squad, followed up in 1998.', 'https://media.retroachievements.org/Images/040086.png', 'https://media.retroachievements.org/Images/016994.png', 'https://media.retroachievements.org/Images/016892.png', 'https://media.retroachievements.org/Images/016893.png', 4.3),
  (61, 11794, 'Mega Man: The Power Battle', 'Arcade', 27, 1557, 1557, 1557, 60, 0, '2D Fighting', 'Capcom', 'Capcom', '1995-10-06', 'Mega Man: The Power Battle is a 1995 fighting game developed and published by Capcom for arcades. A spin-off title for the Mega Man series, it features Mega Man and his allies fighting Doctor Wily and his rebuilt Robot Masters in a series of boss battles. The game was followed by a sequel, Mega Man 2: The Power Fighters, in 1996. Both games have since received home releases through various video game compilations.', 'https://media.retroachievements.org/Images/029567.png', 'https://media.retroachievements.org/Images/018917.png', 'https://media.retroachievements.org/Images/018915.png', 'https://media.retroachievements.org/Images/018916.png', 4.3),
  (62, 13648, 'Battle Garegga', 'Arcade', 27, 1525, 1525, 1525, 30, 0, 'Shoot ''em Up', 'Raizing | Eighting', 'Raizing | Eighting', '1996-02-01', 'Battle Garegga is a vertically scrolling shooter arcade video game developed by Raizing and published by Eighting in 1996. A port to the Saturn was published in 1998. An updated version, Battle Garegga Rev.2016 was released in 2016. It was followed by a spiritual successor, Battle Bakraid, in 1999.', 'https://media.retroachievements.org/Images/066365.png', 'https://media.retroachievements.org/Images/058176.png', 'https://media.retroachievements.org/Images/021414.png', 'https://media.retroachievements.org/Images/021415.png', 4.3),
  (63, 11801, 'Blue''s Journey', 'Arcade', 27, 1523, 1523, 1523, 97, 0, '2D Platforming', 'ADK', 'ADK', '1991-03-01', 'Blue''s Journey is a side-scrolling platform game released by Alpha Denshi in 1990 on SNK''s Neo Geo MVS arcade system and their AES home system. It was ported to the Neo Geo CD in 1994. It was rereleased on the Wii''s Virtual Console in Europe on November 9, 2007, followed by North America on November 12, 2007.', 'https://media.retroachievements.org/Images/043224.png', 'https://media.retroachievements.org/Images/043226.png', 'https://media.retroachievements.org/Images/021945.png', 'https://media.retroachievements.org/Images/043225.png', 4.3),
  (64, 12183, 'Hook', 'Arcade', 27, 1505, 1505, 1505, 89, 0, 'Beat ''em Up', 'Irem', 'Irem', '1992-12-01', 'A hook is a tool consisting of a length of material, typically metal, that contains a portion that is curved/bent back or has a deeply grooved indentation, which serves to grab, latch or in any way attach itself onto another object. The hook''s design allows traction forces to be relayed through the curved/indented portion to and from the proximal end of the hook, which is either a straight shaft or a ring for attachment to a thread, rope or chain, providing a reversible attachment between two objects.', 'https://media.retroachievements.org/Images/039733.png', 'https://media.retroachievements.org/Images/030987.png', 'https://media.retroachievements.org/Images/030986.png', 'https://media.retroachievements.org/Images/030985.png', 4.3),
  (65, 11765, 'Baseball Stars 2', 'Arcade', 27, 1504, 1504, 1504, 43, 0, 'Sports - Baseball', 'SNK', 'SNK', '1992-04-01', 'Baseball Stars 2 is a baseball sports arcade game released by SNK in 1992 for the Neo-Geo console. A less detailed console version was released for the NES by Romstar the same year.', 'https://media.retroachievements.org/Images/041768.png', 'https://media.retroachievements.org/Images/016997.png', 'https://media.retroachievements.org/Images/017006.png', 'https://media.retroachievements.org/Images/017007.png', 4.3),
  (66, 11780, 'Dungeons & Dragons: Shadow Over Mystara', 'Arcade', 27, 1503, 1503, 1503, 51, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1996-02-01', 'Dungeons & Dragons: Shadow over Mystara is a 1996 beat ''em up game developed and published by Capcom for arcades. It is a sequel to Dungeons & Dragons: Tower of Doom. The game is set in the Dungeons & Dragons campaign setting of Mystara.', 'https://media.retroachievements.org/Images/122043.png', 'https://media.retroachievements.org/Images/025286.png', 'https://media.retroachievements.org/Images/025288.png', 'https://media.retroachievements.org/Images/025287.png', 4.3),
  (67, 12366, 'RoboCop', 'Arcade', 27, 1501, 1501, 1501, 43, 0, NULL, 'Data East', 'Data East', '1988-01-01', 'RoboCop is a 1987 American science fiction action film directed by Paul Verhoeven and written by Edward Neumeier and Michael Miner. The film stars Peter Weller, Nancy Allen, Daniel O''Herlihy, Ronny Cox, Kurtwood Smith, and Miguel Ferrer. Set in a crime-ridden Detroit in the near future, RoboCop centers on police officer Alex Murphy (Weller) who is murdered by a gang of criminals and revived by the megacorporation Omni Consumer Products as the cyborg law enforcer RoboCop. Unaware of his former life, RoboCop executes a campaign against crime while coming to terms with the lingering fragments of his humanity.', 'https://media.retroachievements.org/Images/051955.png', 'https://media.retroachievements.org/Images/034893.png', 'https://media.retroachievements.org/Images/050626.png', 'https://media.retroachievements.org/Images/050627.png', 4.3),
  (68, 13794, 'Mutation Nation', 'Arcade', 27, 1487, 1487, 1487, 29, 0, 'Beat ''em Up', 'SNK', 'SNK', '1992-03-01', 'Mutation Nation is a beat ''em up arcade video game that was developed and released by SNK for the Neo Geo in 1992.', 'https://media.retroachievements.org/Images/033279.png', 'https://media.retroachievements.org/Images/033278.png', 'https://media.retroachievements.org/Images/022145.png', 'https://media.retroachievements.org/Images/022146.png', 4.3),
  (69, 14978, 'Mortal Kombat II', 'Arcade', 27, 1486, 1486, 1486, 43, 0, '2D Fighting', 'Midway', 'Midway', '1993-04-03', 'Mortal Kombat II is a 1993 fighting game developed and published by Midway for arcades. It was later ported to multiple home systems, including MS-DOS, Amiga, Game Boy, Game Gear, Sega Genesis, 32X, Sega Saturn, Super NES, and PlayStation, by Probe Software and Sculptured Software, and published by Acclaim Entertainment.', 'https://media.retroachievements.org/Images/122179.png', 'https://media.retroachievements.org/Images/030490.png', 'https://media.retroachievements.org/Images/030935.png', 'https://media.retroachievements.org/Images/030936.png', 4.3),
  (70, 12023, 'Bubble Bobble', 'Arcade', 27, 1453, 1453, 1453, 91, 0, '2D Platforming', 'Taito', 'Electrocoin, Romstar, Taito', '1986-09-01', 'Bubble Bobble is a platform game series originally developed and published by Taito. The first entry in the series, Bubble Bobble, was released in 1986 as an arcade cabinet. In most entries in the series, players control two dragons named Bub and Bob. This was followed by many sequels in both the main Bubble Bobble series, as well as the spin-off Rainbow Islands and Puzzle Bobble series. They were published for and ported to a wide variety of arcade and home video game consoles. The most recent release in the series is Bubble Bobble Sugar Dungeons in 2025.', 'https://media.retroachievements.org/Images/086846.png', 'https://media.retroachievements.org/Images/057562.png', 'https://media.retroachievements.org/Images/057560.png', 'https://media.retroachievements.org/Images/057561.png', 4.3),
  (71, 11959, '64th. Street: A Detective Story', 'Arcade', 27, 1448, 1448, 1448, 15, 0, 'Beat ''em Up', 'C.P. Brain', 'Jaleco', '1991-01-01', '64th Street: A Detective Story is a 1992 beat ''em up video game developed by CP.Brain and published by Jaleco for arcades. It was released in Japan in March 1992 and in North America the same year. The two main characters are private detectives, who fight gangs through six stages to rescue a rich man''s daughter who has been kidnapped.', 'https://media.retroachievements.org/Images/050582.png', 'https://media.retroachievements.org/Images/050736.png', 'https://media.retroachievements.org/Images/050580.png', 'https://media.retroachievements.org/Images/050579.png', 4.3),
  (72, 11768, 'Shock Troopers: 2nd Squad', 'Arcade', 27, 1434, 1434, 1434, 45, 0, NULL, 'Saurus', 'Saurus', '1998-10-01', 'Shock Troopers: 2nd Squad is a run and gun arcade game developed by Saurus and published by SNK in 1998 for the Neo-Geo arcade and home platform. Despite its title, it has no connection with the first Shock Troopers game. 2nd Squad was re-released for the Wii''s Virtual Console service for North America in 2012. SNK Playmore released it for iOS, Linux and Windows via Humble Bundle and Steam in 2016.', 'https://media.retroachievements.org/Images/040175.png', 'https://media.retroachievements.org/Images/016995.png', 'https://media.retroachievements.org/Images/016903.png', 'https://media.retroachievements.org/Images/016904.png', 4.3),
  (73, 11993, 'Battle Circuit', 'Arcade', 27, 1423, 1423, 1423, 48, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1997-03-19', 'The history of video games began in the 1950s and 1960s as computer scientists began designing simple games and simulations on minicomputers and mainframes. Spacewar! was developed by Massachusetts Institute of Technology (MIT) student hobbyists in 1962 as one of the first such games on a video display. The first consumer video game hardware was released in the early 1970s. The first home video game console was the Magnavox Odyssey, and the first arcade video games were Computer Space and Pong. After its home console conversions, numerous companies sprang up to capture Pong''s success in both the arcade and the home by cloning the game, causing a series of boom and bust cycles due to oversaturation and lack of innovation.', 'https://media.retroachievements.org/Images/073731.png', 'https://media.retroachievements.org/Images/065022.png', 'https://media.retroachievements.org/Images/069928.png', 'https://media.retroachievements.org/Images/069930.png', 4.3),
  (74, 13808, 'Robo Army', 'Arcade', 27, 1418, 1418, 1418, 26, 0, 'Beat ''em Up', 'SNK', 'SNK', '1991-10-30', 'Robo Army is a beat ''em up video game developed and published by SNK that was released for Neo Geo arcades and home consoles in 1991 and the Neo Geo CD in 1995.', 'https://media.retroachievements.org/Images/077448.png', 'https://media.retroachievements.org/Images/039393.png', 'https://media.retroachievements.org/Images/022256.png', 'https://media.retroachievements.org/Images/022257.png', 4.3),
  (75, 12032, 'The King of Fighters ''99: Millennium Battle', 'Arcade', 27, 1406, 1406, 1406, 74, 0, '2D Fighting', 'SNK', 'SNK', '1999-07-22', 'The King of Fighters ''99: Millennium Battle, also called KOF ''99, is a 1999 fighting game developed and published by SNK for the Neo Geo MVS arcade and home consoles in 1999. It is the sixth installment in The King of Fighters series following The King of Fighters ''98, introducing a new story arc known as the NESTS Chronicles which is centered around a young man named K'', who is formerly associated with a mysterious organization known only as NESTS. The game introduces several changes to the established KOF format, most notably an assisting character labeled Striker. The game was ported to the Neo Geo CD and the PlayStation. Dreamcast and Microsoft Windows versions were also released under the title The King of Fighters'' 99: Evolution whose stages were remodeled in 3D.', 'https://media.retroachievements.org/Images/120962.png', 'https://media.retroachievements.org/Images/016424.png', 'https://media.retroachievements.org/Images/016412.png', 'https://media.retroachievements.org/Images/016418.png', 4.3),
  (76, 17678, 'Spider-Man: The Videogame', 'Arcade', 27, 1388, 1388, 1388, 9, 0, 'Beat ''em Up', 'Sega', 'Sega', '1991-09-01', 'Spider-Man: The Video Game, also known as Spider-Man, is a 1991 arcade video game developed by Sega based on the Marvel Comics character Spider-Man.', 'https://media.retroachievements.org/Images/107611.png', 'https://media.retroachievements.org/Images/046461.png', 'https://media.retroachievements.org/Images/046459.png', 'https://media.retroachievements.org/Images/046462.png', 4.3),
  (77, 11853, 'Shinobi', 'Arcade', 27, 1349, 1349, 1349, 28, 0, NULL, 'Sega', 'Sega', '1987-11-01', 'A ninja , shinobi no mono  or shinobi  was a spy and infiltrator in pre-modern Japan. Antecedents may have existed as early as the 12th century. There is little evidence that they were assassins.', 'https://media.retroachievements.org/Images/110100.png', 'https://media.retroachievements.org/Images/057191.png', 'https://media.retroachievements.org/Images/019173.png', 'https://media.retroachievements.org/Images/019174.png', 4.3),
  (78, 13784, 'King of the Monsters', 'Arcade', 27, 1347, 1347, 1347, 49, 0, 'Fighting (Kaiju, Wrestling)', 'SNK', 'SNK', '1991-02-01', 'King of the Monsters is a fighting game developed by SNK, released for arcades in Japan in 1991, and ported to the Neo Geo AES later that same year. The game features playable giant monsters that are reminiscent of characters from kaiju and tokusatsu films.', 'https://media.retroachievements.org/Images/033265.png', 'https://media.retroachievements.org/Images/033264.png', 'https://media.retroachievements.org/Images/022055.png', 'https://media.retroachievements.org/Images/022056.png', 4.3),
  (79, 14654, 'Ultimate Mortal Kombat 3', 'Arcade', 27, 1334, 1334, 1334, 65, 0, '2D Fighting', 'Midway', 'Midway', '1995-11-06', 'Ultimate Mortal Kombat 3 is a 1995 fighting game developed and published by Midway for arcades. Part of the Mortal Kombat series, it is a standalone update of 1995''s earlier Mortal Kombat 3 with an altered gameplay system and some new features, as well as additional characters like the returning favorites Reptile, Kitana, Jade and Scorpion, who were missing from Mortal Kombat 3.', 'https://media.retroachievements.org/Images/122181.png', 'https://media.retroachievements.org/Images/055562.png', 'https://media.retroachievements.org/Images/027506.png', 'https://media.retroachievements.org/Images/027507.png', 4.3),
  (80, 11946, 'Mario Bros.', 'Arcade', 27, 1329, 1329, 1329, 22, 0, '2D Platforming', NULL, 'Nintendo', '1983-07-14', 'Mario Bros. is a 1983 platform game developed and published by Nintendo for arcades. It was designed by Shigeru Miyamoto and Gunpei Yokoi, Nintendo''s chief engineer. Players control Italian twin brother plumbers Mario and Luigi as they exterminate turtle-like creatures, giant flies, and crabs emerging from the sewers of New York City by knocking them upside-down and kicking them away. The Famicom/NES version was the first game to be developed by Intelligent Systems. It is part of the Mario franchise and the first spin-off of the Donkey Kong series.', 'https://media.retroachievements.org/Images/060942.png', 'https://media.retroachievements.org/Images/019366.png', 'https://media.retroachievements.org/Images/019363.png', 'https://media.retroachievements.org/Images/019364.png', 4.3),
  (81, 12261, 'Street Fighter', 'Arcade', 27, 1320, 1320, 1320, 39, 0, '2D Fighting', 'Capcom', 'Capcom', '1987-08-30', 'Street Fighter is a Japanese media franchise centered on a series of fighting games developed and published by Capcom. The first game in the series was released in 1987, followed by the other six main games in the series, various spin-offs and crossovers, and numerous appearances in other media. Its best-selling 1991 release, Street Fighter II, established many of the conventions of the one-on-one fighting genre.', 'https://media.retroachievements.org/Images/070391.png', 'https://media.retroachievements.org/Images/115504.png', 'https://media.retroachievements.org/Images/049573.png', 'https://media.retroachievements.org/Images/049574.png', 4.3),
  (82, 12380, 'Strikers 1945', 'Arcade', 27, 1301, 1301, 1301, 39, 0, 'Shoot ''em Up', 'Psikyo', 'Psikyo', '1995-01-01', 'Strikers 1945 (ストライカーズ1945), also known as Striker 1945, is a vertically scrolling shoot ''em up bullet hell arcade game developed and published by Psikyo in 1995. In Japan, it was ported to the PlayStation and Sega Saturn by Atlus in 1996; later was also released as part of Psikyo Shooting Collection Vol. 1: Strikers 1945 I & II by Taito for the PlayStation 2. The game was followed by Strikers 1945 II in 1997, and Strikers 1945 III in 1999, as well as the second title remake called Strikers 1945 Plus.', 'https://media.retroachievements.org/Images/068029.png', 'https://media.retroachievements.org/Images/025230.png', 'https://media.retroachievements.org/Images/025228.png', 'https://media.retroachievements.org/Images/025229.png', 4.3),
  (83, 12139, 'Galaxian', 'Arcade', 27, 1296, 1296, 1296, 24, 0, 'Shoot ''em Up', 'Namco', 'Midway', '1979-10-01', 'Galaxian is a 1979 fixed shooter video game developed and published by Namco for arcades during early video games'' golden age. The player assumes control of the Galaxip starfighter in its mission to protect Earth from waves of aliens. Gameplay involves destroying each formation of aliens, who dive down towards the player in an attempt to hit them.', 'https://media.retroachievements.org/Images/119282.png', 'https://media.retroachievements.org/Images/073953.png', 'https://media.retroachievements.org/Images/033527.png', 'https://media.retroachievements.org/Images/033528.png', 4.3),
  (84, 15015, 'Centipede', 'Arcade', 27, 1290, 1290, 1290, 40, 0, 'Shoot ''em Up', 'Atari', 'Atari', '1981-06-15', 'Centipedes are predatory arthropods belonging to the class Chilopoda of the subphylum Myriapoda, an arthropod group which includes millipedes and other multi-legged animals. Centipedes are elongated segmented (metameric) animals with one pair of legs per body segment. All centipedes are venomous and can inflict painful stings, injecting their venom through pincer-like appendages known as forcipules or toxicognaths, which are actually modified legs instead of fangs. Despite the name, no species of centipede has exactly 100 legs; the number of pairs of legs is an odd number that ranges from 15 pairs to 191 pairs.', 'https://media.retroachievements.org/Images/103392.png', 'https://media.retroachievements.org/Images/085580.png', 'https://media.retroachievements.org/Images/085579.png', 'https://media.retroachievements.org/Images/086284.png', 4.3),
  (85, 12005, 'Detana!! TwinBee', 'Arcade', 27, 1290, 1290, 1290, 40, 0, 'Shoot ''em Up', 'Konami', 'Konami', '1991-02-01', 'Detana!! TwinBee, released in Europe as Bells & Whistles, is a 1991 vertically scrolling shooter video game developed and published by Konami for arcades. It is the fifth entry in the TwinBee series and the second to be released for arcades following the original TwinBee. Set several years after the events of TwinBee, players assume the role of Light and Pastel taking control of TwinBee and WinBee to defeat invading forces of the evil alien Iva and save planet Meru after receiving an SOS message sent by Princess Melora.', 'https://media.retroachievements.org/Images/052612.png', 'https://media.retroachievements.org/Images/052964.png', 'https://media.retroachievements.org/Images/052587.png', 'https://media.retroachievements.org/Images/052588.png', 4.3),
  (86, 11942, 'X-Men vs. Street Fighter', 'Arcade', 27, 1259, 1259, 1259, 55, 0, '2D Fighting', 'Capcom', 'Capcom', '1996-09-01', 'X-Men vs. Street Fighter is a 1996 crossover fighting game developed and published by Capcom. It is Capcom''s third fighting game to feature Marvel Comics characters, following X-Men: Children of the Atom (1994) and Marvel Super Heroes (1995), and the first installment in the Marvel vs. Capcom series. As the title suggests, the game includes characters from Marvel''s X-Men franchise and the cast from Capcom''s Street Fighter series. Originally released for arcades in 1996, it was ported to the Sega Saturn in 1997 and the PlayStation in 1998. The original arcade version is included in the compilation Marvel vs. Capcom Fighting Collection: Arcade Classics, released for the Nintendo Switch, PlayStation 4 and Windows in 2024.', 'https://media.retroachievements.org/Images/106810.png', 'https://media.retroachievements.org/Images/016185.png', 'https://media.retroachievements.org/Images/016182.png', 'https://media.retroachievements.org/Images/016183.png', 4.3),
  (87, 11858, 'Bang Bead', 'Arcade', 27, 1241, 1241, 1241, 17, 0, 'Sports - Ball & Paddle', 'Visco', 'Visco', '2000-01-01', 'Japanese video game company SNK began developing and publishing video games in 1978. SNK''s first video games were released on dedicated arcade boards throughout the 1980s. In the 1990s and early 2000s, most of their games were released on their proprietary hardware, including the Neo Geo and Neo Geo Pocket Color. Since the mid-2000s, SNK has released games on other company platforms.', 'https://media.retroachievements.org/Images/088064.png', 'https://media.retroachievements.org/Images/099018.png', 'https://media.retroachievements.org/Images/021939.png', 'https://media.retroachievements.org/Images/021940.png', 4.3),
  (88, 4845, 'Pretty Soldier Sailor Moon', 'Arcade', 27, 1220, 1220, 1220, 30, 0, 'Beat ''em Up', 'Gazelle', 'Banpresto', '1995-03-22', 'Pretty Soldier Sailor Moon is a side-scrolling beat ''em up arcade video game developed by Gazelle and released on March 22, 1995. It was published by Banpresto. It is the first game to be created by Gazelle, one of the offshoots of defunct developer Toaplan that were founded after they declared bankruptcy in 1994, and one of the few titles based upon Naoko Takeuchi''s Sailor Moon shōjo manga and anime series that had an official international release, and it also has been compared with other titles in the same genre such as Capcom''s Final Fight and Technōs Japan''s Double Dragon.', 'https://media.retroachievements.org/Images/068543.png', 'https://media.retroachievements.org/Images/031271.png', 'https://media.retroachievements.org/Images/029089.png', 'https://media.retroachievements.org/Images/029097.png', 4.3),
  (89, 15000, 'Batman', 'Arcade', 27, 1215, 1215, 1215, 19, 0, 'Beat ''em Up', 'Atari', 'Atari', '1991-04-01', 'Batman is a superhero who appears in American comic books published by DC Comics. Batman was created by writer Bill Finger and artist Bob Kane, and debuted in the 27th issue of the comic book Detective Comics on March 30, 1939. In the DC Universe, Batman is the alias of Bruce Wayne, a wealthy American playboy, philanthropist, and industrialist who resides in the fictional Gotham City. Originally a millionaire, later versions of the character depict him as a billionaire. His origin story features him swearing vengeance against criminals after witnessing the murder of his parents, Thomas and Martha, as a child, a vendetta tempered by the ideal of justice. He trains himself physically and intellectually, crafts a bat-inspired persona, and monitors the Gotham streets at night. Kane, Finger, and other creators accompanied Batman with supporting characters, including his sidekicks Robin and Batgirl; allies Alfred Pennyworth and James Gordon; love interest and occasional adversary Catwoman; as well as foes such as the Penguin, the Riddler, Two-Face, and his archenemy, the Joker.', 'https://media.retroachievements.org/Images/052559.png', 'https://media.retroachievements.org/Images/030277.png', 'https://media.retroachievements.org/Images/030276.png', 'https://media.retroachievements.org/Images/030278.png', 4.3),
  (90, 12033, 'The King of Fighters 2000', 'Arcade', 27, 1214, 1214, 1214, 90, 0, '2D Fighting', 'SNK', 'SNK', '2000-07-01', 'The King of Fighters 2000 is a 2000 fighting video game developed and produced by SNK and released for the Neo Geo arcade and home consoles. It is the seventh installment in The King of Fighters series for the Neo Geo, and the final game in the series SNK produced before the original company''s bankruptcy. The game was ported to the Dreamcast in Japan and the PlayStation 2 in 2002. The game, a sequel to The King of Fighters ''99, focuses on a tournament held by the commander of the Hikari military forces, Heidern, who seeks to interrogate the missing K'' and Maxima in order to learn about their former group, the NESTS cartel. The gameplay retains the Striker system of the previous games in the series involving assisting characters, but was modified to generate more combos.', 'https://media.retroachievements.org/Images/109347.png', 'https://media.retroachievements.org/Images/016470.png', 'https://media.retroachievements.org/Images/016462.png', 'https://media.retroachievements.org/Images/016469.png', 4.3),
  (91, 12030, 'The King of Fighters ''96', 'Arcade', 27, 1208, 1208, 1208, 96, 0, '2D Fighting', 'SNK', 'SNK', '1996-07-01', 'The King of Fighters ''96 (KOF ''96) is a fighting game released by SNK for the Neo Geo arcade and home consoles in 1996. It is the third game in The King of Fighters series, following The King of Fighters ''95. Unlike its predecessors, it features more emphasis on hand-to-hand combat rather than projectile moves. The plot follows a new King of Fighters tournament created by Chizuru Kagura, the heir of the Yata Clan, who wants to find and recruit the protagonist, Kyo Kusanagi, who defeated the previous host Rugal Bernstein. She seeks to recruit him to ask him and his bitter rival, Iori Yagami, to help her in the sealing of the Orochi demon like her predecessors. The final boss of the game is Goenitz, one of the servants of Orochi. Developers made several changes to the cast when compared to The King of Fighters ''95, with special focus on a Boss Team composed of famous villains from their other two IPs, Fatal Fury and Art of Fighting.', 'https://media.retroachievements.org/Images/120960.png', 'https://media.retroachievements.org/Images/016421.png', 'https://media.retroachievements.org/Images/016410.png', 'https://media.retroachievements.org/Images/016415.png', 4.3),
  (92, 12082, 'Double Dragon', 'Arcade', 27, 1202, 1202, 1202, 16, 0, 'Beat ''em Up', 'Technos Japan', 'Taito', '1987-01-01', 'Double Dragon  is a beat ''em up video game series originally developed and published by Technōs Japan. It began with the release of the arcade game Double Dragon in 1987. The series features twin martial artists, Billy and Jimmy Lee, as they fight against various adversaries and rivals.', 'https://media.retroachievements.org/Images/049791.png', 'https://media.retroachievements.org/Images/055660.png', 'https://media.retroachievements.org/Images/054631.png', 'https://media.retroachievements.org/Images/054632.png', 4.3),
  (93, 12149, 'Ghosts ''n Goblins', 'Arcade', 27, 1198, 1198, 1198, 42, 0, NULL, 'Capcom', 'Capcom', '1985-09-01', 'Ghosts ''n Goblins, known in Japan as Makaimura , is a series of run-and-gun platform video games developed and owned by Capcom. The first entry in the series was Ghosts ''n Goblins, released in arcades on July 7, 1985. The series has subsequently been ported to and released on a variety of personal computers, game consoles and mobile platforms and spawned several sequels and spin-offs.', 'https://media.retroachievements.org/Images/119126.png', 'https://media.retroachievements.org/Images/050116.png', 'https://media.retroachievements.org/Images/032357.png', 'https://media.retroachievements.org/Images/044934.png', 4.3),
  (94, 12661, 'Double Dragon (Neo-Geo)', 'Arcade', 27, 1195, 1195, 1195, 38, 0, '2D Fighting', 'Technōs Japan', 'Technōs Japan', '1995-02-01', 'Double Dragon  is a beat ''em up video game series originally developed and published by Technōs Japan. It began with the release of the arcade game Double Dragon in 1987. The series features twin martial artists, Billy and Jimmy Lee, as they fight against various adversaries and rivals.', 'https://media.retroachievements.org/Images/120099.png', 'https://media.retroachievements.org/Images/048755.png', 'https://media.retroachievements.org/Images/063513.png', 'https://media.retroachievements.org/Images/048756.png', 4.3),
  (95, 13566, 'Pachinko Sexy Reaction', 'Arcade', 27, 1187, 1187, 1187, 15, 0, 'Casino, Pachinko', 'Sammy', 'Sammy', '1998-01-01', 'The Sega Saturn is a 32-bit fifth-generation home video game console that was developed by Sega and first released on November 22, 1994. Its games are in CD-ROM format, and its game library contains several arcade ports as well as original titles. There are 1028 games on this list not including non-game software and compilations of Saturn games. 775 of those games were released as Japan-only exclusives, which makes up 75% of the list. For games that were announced or in development for the Saturn, but never released, see the list of cancelled Sega Saturn games.', 'https://media.retroachievements.org/Images/034082.png', 'https://media.retroachievements.org/Images/034109.png', 'https://media.retroachievements.org/Images/021172.png', 'https://media.retroachievements.org/Images/034083.png', 4.3),
  (96, 11979, 'U.N. Squadron', 'Arcade', 27, 1173, 1173, 1173, 52, 0, 'Shoot ''em Up', 'Capcom', 'Capcom', '1989-08-01', 'U.N. Squadron, released in Japan as Area 88, is a 1989 side-scrolling shooter video game developed and published by Capcom for arcades. It was based on the manga series of the same name, though the North American release omits all references to the manga. Their mission is to stop a terrorist group known as Project 4. It was ported to multiple platforms including the Super Nintendo Entertainment System and was followed by a spiritual successor, Carrier Air Wing.', 'https://media.retroachievements.org/Images/061639.png', 'https://media.retroachievements.org/Images/061309.png', 'https://media.retroachievements.org/Images/061344.png', 'https://media.retroachievements.org/Images/061342.png', 4.3),
  (97, 17469, 'SegaSonic the Hedgehog', 'Arcade', 27, 1170, 1170, 1170, 40, 0, '2.5D Platforming', NULL, 'Sega', '1993-06-01', 'SegaSonic the Hedgehog is a 1993 arcade game in the Sonic the Hedgehog series by Sega. Controlling Sonic the Hedgehog and his friends Mighty the Armadillo and Ray the Flying Squirrel, the player must escape an island after they are kidnapped by the villain, Doctor Eggman. The game uses an isometric perspective. Players use a trackball to move the characters while dodging obstacles and collecting rings. The game was developed by Sega''s arcade division, Sega AM3. It is one of four Sonic games with the SegaSonic name and was inspired by the 1984 game Marble Madness.', 'https://media.retroachievements.org/Images/108435.png', 'https://media.retroachievements.org/Images/049039.png', 'https://media.retroachievements.org/Images/049031.png', 'https://media.retroachievements.org/Images/049032.png', 4.3),
  (98, 13250, 'Night Slashers', 'Arcade', 27, 1158, 1158, 1158, 32, 0, 'Beat ''em Up', 'Data East', 'Data East', '1993-09-01', 'Night Slashers (ナイトスラッシャーズ) is a 1993 beat ''em up game developed and published by Data East for arcades. A remake for major platforms was licensed to Forever Entertainment, developed by Storm Trident, and released in September 2024.', 'https://media.retroachievements.org/Images/113579.png', 'https://media.retroachievements.org/Images/019178.png', 'https://media.retroachievements.org/Images/019179.png', 'https://media.retroachievements.org/Images/019180.png', 4.2),
  (99, 13815, 'Super Sidekicks 3: The Next Glory', 'Arcade', 27, 1158, 1158, 1158, 21, 0, NULL, 'SNK', 'SNK', '1995-03-01', 'Super Sidekicks 3: The Next Glory is a 1995 soccer arcade video game developed and published by SNK. It is the third installment in the Super Sidekicks series, succeeding Super Sidekicks 2: The World Championship (1994). Featuring an arcade-style approach to soccer like its predecessors, the game allows players to choose any of the available game modes to compete with AI-controlled rivals or other human players with their preferred team. Though first launched for the MVS hardware, the title was ported for Neo Geo AES and Neo Geo CD, in addition of being re-released through compilations and download services for various consoles. It proved popular among players and garnered positive reception from critics, but most reviewers noted that it felt more an update than a true successor to Super Sidekicks 2. It was followed by The Ultimate 11: SNK Football Championship in 1996.', 'https://media.retroachievements.org/Images/067066.png', 'https://media.retroachievements.org/Images/067065.png', 'https://media.retroachievements.org/Images/068062.png', 'https://media.retroachievements.org/Images/068063.png', 4.2),
  (100, 11760, 'Zed Blade', 'Arcade', 27, 1149, 1149, 1149, 43, 0, 'Shoot ''em Up', 'NMK', 'NMK', '1994-09-01', 'Arcade Archives is a series of emulated arcade games developed and published by Hamster Corporation. A sub-series called ACA Neo Geo focuses on re-releasing SNK''s Neo Geo titles in their original MVS arcade format, unlike many services that attempt to emulate the console versions. Individual games are released in a weekly format. Another sub-series called Console Archives focuses on releasing home console video games.', 'https://media.retroachievements.org/Images/032828.png', 'https://media.retroachievements.org/Images/032829.png', 'https://media.retroachievements.org/Images/022360.png', 'https://media.retroachievements.org/Images/022361.png', 4.2),
  (101, 12526, 'Space Invaders', 'Arcade', 27, 1125, 1125, 1125, 22, 0, 'Shoot ''em Up', NULL, 'LAI Games, Midway, Taito', '1978-04-19', 'Space Invaders is a 1978 shoot ''em up video game developed and published by Taito for arcades. It was released in Japan in April 1978, and released overseas by Midway Manufacturing later that year. Space Invaders was the first video game with endless gameplay and the first fixed shooter, setting the template for the genre. The goal is to defeat waves of descending aliens with a horizontally moving laser cannon to earn as many points as possible.', 'https://media.retroachievements.org/Images/069896.png', 'https://media.retroachievements.org/Images/066548.png', 'https://media.retroachievements.org/Images/069779.png', 'https://media.retroachievements.org/Images/069781.png', 4.2),
  (102, 12816, 'Goal! Goal! Goal!', 'Arcade', 27, 1120, 1120, 1120, 50, 0, 'Sports - Football | Soccer', 'Visco', 'Visco', '1995-01-01', 'Goal! Goal! Goal! is a football/soccer video game developed by Visco and published by SNK in 1995 for the Neo-Geo console.', 'https://media.retroachievements.org/Images/063175.png', 'https://media.retroachievements.org/Images/017138.png', 'https://media.retroachievements.org/Images/017141.png', 'https://media.retroachievements.org/Images/028322.png', 4.2),
  (103, 12028, 'The King of Fighters ''94', 'Arcade', 27, 1109, 1109, 1109, 49, 0, NULL, 'SNK', 'SNK', '1994-08-01', 'The King of Fighters ''94 is a fighting game released in 1994, developed and published by SNK for the Neo Geo MVS arcade system, AES, and CD home consoles. It is a crossover game, featuring characters from SNK’s earlier titles, including Fatal Fury and Art of Fighting, updated versions of characters from Ikari Warriors and Psycho Soldier, and new, original characters. The story centers around the tournament organized by the antagonist Rugal Bernstein.', 'https://media.retroachievements.org/Images/109363.png', 'https://media.retroachievements.org/Images/016419.png', 'https://media.retroachievements.org/Images/016407.png', 'https://media.retroachievements.org/Images/016413.png', 4.2),
  (104, 12165, 'GunForce II', 'Arcade', 27, 1108, 1108, 1108, 28, 0, 'Run & Gun', 'Irem', 'Irem', '1994-09-01', 'GunForce II is a run and gun arcade video game developed and originally published by Irem in September 1994. It is the sequel to the original GunForce and one of the last arcade games, if not the last to be released by the company before ceasing development of video games in the same year, after which a group of employees from the gaming division of Irem would go on to form Nazca Corporation due to being tired of the company''s inactivity.', 'https://media.retroachievements.org/Images/063750.png', 'https://media.retroachievements.org/Images/030974.png', 'https://media.retroachievements.org/Images/030972.png', 'https://media.retroachievements.org/Images/063648.png', 4.2),
  (105, 21889, 'Deathsmiles', 'Arcade', 27, 1107, 1107, 1107, 48, 0, 'Shoot ''em Up, Bullet Hell', 'CAVE Interactive', 'AMI', '2007-10-19', 'Deathsmiles  is a horizontally scrolling shooter arcade video game by Japanese developer Cave, released in late 2007. It has heavy occult and gothic influences. It is the second Cave shooter to be played using a horizontally-oriented monitor. It was the first Cave shooter released in North America on a console, and the first one in Europe. Cave has also released it for iOS. A sequel, Deathsmiles II, was released to Japanese arcades on May 14, 2009. A compilation of both Deathsmiles I and Deathsmiles II was released for PlayStation 4, Xbox One and Nintendo Switch in Japan on December 16, 2021.', 'https://media.retroachievements.org/Images/113433.png', 'https://media.retroachievements.org/Images/091983.png', 'https://media.retroachievements.org/Images/084828.png', 'https://media.retroachievements.org/Images/091984.png', 4.2),
  (106, 12163, 'Gunbird', 'Arcade', 27, 1107, 1107, 1107, 19, 0, 'Shoot ''em Up', 'Psikyo', 'Psikyo, Jaleco', '1993-03-22', 'Gunbird (ガンバード) is a vertically scrolling shooter developed by Psikyo and released as an arcade video game in 1994. In the US, it was published by Jaleco. It has been re-released multiple times, including on the Sega Saturn, PlayStation, Steam, Nintendo Switch, PlayStation 4 and Xbox One. When originally localized outside Japan by XS Games, Gunbird was retitled Mobile Light Force. The game was followed by Gunbird 2 in 1998 and was included in Gunbird Special Edition for PlayStation 2.', 'https://media.retroachievements.org/Images/077869.png', 'https://media.retroachievements.org/Images/077922.png', 'https://media.retroachievements.org/Images/077867.png', 'https://media.retroachievements.org/Images/077868.png', 4.2),
  (107, 11805, 'Street Fighter Alpha: Warriors'' Dreams', 'Arcade', 27, 1107, 1107, 1107, 44, 0, '2D Fighting', 'Capcom', 'Capcom', '1995-01-01', 'Street Fighter Alpha: Warriors'' Dreams, known as Street Fighter Zero in Japan, Asia, South America, and Oceania, is a 1995 fighting game developed and published by Capcom for arcades. It was the first all-new Street Fighter game produced by Capcom since 1991''s Street Fighter II. Plotwise, it serves as a prequel to Street Fighter II and thus features younger versions of established characters, as well as characters from the original Street Fighter and Final Fight.', 'https://media.retroachievements.org/Images/016030.png', 'https://media.retroachievements.org/Images/016029.png', 'https://media.retroachievements.org/Images/016027.png', 'https://media.retroachievements.org/Images/016028.png', 4.2),
  (108, 12538, 'Magical Drop III', 'Arcade', 27, 1089, 1089, 1089, 54, 0, 'Tile Matching', 'Data East', 'Data East', '1997-02-25', 'Magical Drop III is a 1997 puzzle video game developed and published by Data East for the Neo Geo arcade and home platforms. It was later ported to Sega Saturn, PlayStation, Neo Geo Pocket Color, Game Boy Color, Windows, and Zeebo. It is the third entry in the Magical Drop series. In the game, the player takes control of one of several characters, battling against computer-controlled opponents. Gameplay is similar to previous entries albeit with further additions; the objective is to clear the screen of constantly advancing colored ''drops'' via a character placed at the bottom of the playfield, which can grab drops and make them disappear by putting drops as a column of three or more of the same color. The player can also participate in a board-style adventure mode, while two players can play against each other in a competitive versus mode.', 'https://media.retroachievements.org/Images/077204.png', 'https://media.retroachievements.org/Images/076382.png', 'https://media.retroachievements.org/Images/099432.png', 'https://media.retroachievements.org/Images/099795.png', 4.2),
  (109, 17540, 'Battletoads', 'Arcade', 27, 1077, 1077, 1077, 55, 0, 'Beat ''em Up, Action', 'Rare', 'Electronic Arts', '1994-01-01', 'Battletoads is a video game franchise by Rare that began with the original beat ''em up game Battletoads in 1991. Starring three anthropomorphic toads named after skin conditions, Rash, Zitz, and Pimple, the series was created to rival the Teenage Mutant Ninja Turtles games series. The original Battletoads game for the NES was renowned for its extreme difficulty, but still received a cult following, spawning sequels for various platforms including a crossover with the Double Dragon series and a modern reboot after a 25-year gap in releases. In each of the games, the objective is to defeat the toads'' nemesis the Dark Queen and her army of space mutants.', 'https://media.retroachievements.org/Images/048857.png', 'https://media.retroachievements.org/Images/042978.png', 'https://media.retroachievements.org/Images/042980.png', 'https://media.retroachievements.org/Images/042979.png', 4.2),
  (110, 12514, 'Toki', 'Arcade', 27, 1070, 1070, 1070, 24, 0, '2D Platforming', 'TAD', 'TAD', '1989-01-01', 'Toki Pona is a philosophical and artistic constructed language designed for its small vocabulary, simplicity, and ease of acquisition. It was created by Canadian translator and polyglot Sonja Lang with the stated purpose of simplifying her thoughts and communication. The first drafts were published online in 2001, while the complete form was published in the 2014 book Toki Pona: The Language of Good. Lang also released a supplementary dictionary, the Toki Pona Dictionary, in July 2021, describing the language as used by its community of speakers. In 2024, a third book was released, a Toki Pona adaptation of The Wonderful Wizard of Oz, written in Sitelen Pona.', 'https://media.retroachievements.org/Images/042097.png', 'https://media.retroachievements.org/Images/035639.png', 'https://media.retroachievements.org/Images/035638.png', 'https://media.retroachievements.org/Images/035637.png', 4.2),
  (111, 16492, 'Blood Bros.', 'Arcade', 27, 1069, 1069, 1069, 32, 0, 'Gallery Shooter', 'TAD', 'TAD', '1990-01-01', 'Blood Bros. is a 1990 arcade game developed and published by TAD Corporation in Japan and Europe, and later published in North America by Fabtek. It is a spiritual sequel to the 1988 game Cabal, with almost identical mechanics. A bootleg of Blood Bros. is known as West Story.', 'https://media.retroachievements.org/Images/036082.png', 'https://media.retroachievements.org/Images/036080.png', 'https://media.retroachievements.org/Images/036081.png', 'https://media.retroachievements.org/Images/035754.png', 4.2),
  (112, 11751, 'Blazing Star', 'Arcade', 27, 1061, 1061, 1061, 50, 0, 'Shoot ''em Up', 'Yumekobo', 'SNK', '1998-01-01', 'Blazing Star is a 1998 horizontally scrolling shooter video game developed by Yumekobo and published by SNK for the Neo Geo arcade and home systems. It is a follow-up to Pulstar (1995), and features side-scrolling action similar to its predecessor and different ships with varying characteristics. It was made less challenging than its predecessor, and the graphic quality was improved upon.', 'https://media.retroachievements.org/Images/016053.png', 'https://media.retroachievements.org/Images/016046.png', 'https://media.retroachievements.org/Images/016586.png', 'https://media.retroachievements.org/Images/016587.png', 4.2),
  (113, 12230, 'Super Gem Fighter: Mini Mix', 'Arcade', 27, 1052, 1052, 1052, 50, 0, '2D Fighting', 'Capcom', 'Capcom', '1997-09-01', 'Super Gem Fighter Mini Mix, also released as Pocket Fighter  in Japan, is a 1997 fighting game developed and published by Capcom for arcades. The game uses the same super deformed character designs previously used in Super Puzzle Fighter II Turbo, a puzzle game by Capcom. It was ported in 1998 to the PlayStation, which retained the Pocket Fighter title for its North American and PAL releases, and then the Sega Saturn and WonderSwan, both in Japan only.', 'https://media.retroachievements.org/Images/108609.png', 'https://media.retroachievements.org/Images/037751.png', 'https://media.retroachievements.org/Images/037750.png', 'https://media.retroachievements.org/Images/037747.png', 4.2),
  (114, 12029, 'The King of Fighters ''95', 'Arcade', 27, 1052, 1052, 1052, 57, 0, '2D Fighting', 'SNK', 'SNK', '1995-07-01', 'The King of Fighters ''95 (KOF ''95) is a 1995 fighting video game developed and published by SNK for the Neo Geo arcade system. It is the sequel to The King of Fighters ''94, and the second installment in The King of Fighters series. The game features a similar cast to KOF ''94 with the exception of the USA Team, which was replaced by the Rival Team. The plot features a new King of Fighters tournament once again promoted by the criminal Rugal Bernstein, who seeks revenge against the protagonist Kyo Kusanagi, who defeated him in last year''s tournament. KOF ''95 marks the first appearance of the fighter Iori Yagami, who becomes Kyo''s rival in the series.', 'https://media.retroachievements.org/Images/120959.png', 'https://media.retroachievements.org/Images/016420.png', 'https://media.retroachievements.org/Images/016408.png', 'https://media.retroachievements.org/Images/016414.png', 4.2),
  (115, 11900, 'Mega Man 2: The Power Fighters', 'Arcade', 27, 1051, 1051, 1051, 91, 0, '2D Fighting', 'Capcom', 'Capcom', '1996-08-01', 'Mega Man 2: The Power Fighters is a 1996 fighting game developed and published by Capcom for arcades. A spin-off of the Mega Man series, it is the direct sequel to Mega Man: The Power Battle released the previous year. Both games have since received home releases through various video game compilations.', 'https://media.retroachievements.org/Images/035106.png', 'https://media.retroachievements.org/Images/020122.png', 'https://media.retroachievements.org/Images/019737.png', 'https://media.retroachievements.org/Images/019736.png', 4.2),
  (116, 5645, 'Gaia Crusaders', 'Arcade', 27, 1037, 1037, 1037, 52, 0, 'Beat ''em Up', 'Noise Factory', 'Noise Factory', '1999-07-01', 'This is a list of notable video game companies that have made games for either computers, video game consoles, handheld or mobile devices, and includes companies that currently exist as well as now-defunct companies.', 'https://media.retroachievements.org/Images/038853.png', 'https://media.retroachievements.org/Images/038854.png', 'https://media.retroachievements.org/Images/029093.png', 'https://media.retroachievements.org/Images/029103.png', 4.2),
  (117, 13802, 'Samurai Shodown', 'Arcade', 27, 993, 993, 993, 54, 0, '2D Fighting', 'SNK', 'SNK', '1993-07-01', 'Samurai Shodown, known in Japan as Samurai Spirits, is a fighting game series by SNK. The series began in 1993 and is known for being one of the earliest in the genre with a primary focus on weapon-based combat.', 'https://media.retroachievements.org/Images/108414.png', 'https://media.retroachievements.org/Images/024968.png', 'https://media.retroachievements.org/Images/022214.png', 'https://media.retroachievements.org/Images/022215.png', 4.2),
  (118, 12175, 'Hang-On', 'Arcade', 27, 969, 969, 969, 20, 0, 'Racing', 'Sega', 'Sega', '1985-01-01', 'Hang-On is a 1985 racing video game developed and published by Sega for arcades. In the game, the player controls a motorcycle against time and other computer-controlled bikes. It was one of the first arcade games to use 16-bit graphics and uses the Super Scaler arcade system board, created with design input from Yu Suzuki, as technology to simulate 3D effects. The deluxe cabinet version also introduced a motion-controlled arcade cabinet, where the player''s body movement on a large motorbike-shaped cabinet corresponds with the player character''s movements on screen.', 'https://media.retroachievements.org/Images/053130.png', 'https://media.retroachievements.org/Images/054620.png', 'https://media.retroachievements.org/Images/054619.png', 'https://media.retroachievements.org/Images/054618.png', 4.2),
  (119, 11772, 'Street Fighter II: Champion Edition', 'Arcade', 27, 965, 965, 965, 35, 0, '2D Fighting', 'Capcom', 'Capcom', '1991-01-01', 'Street Fighter II: Champion Edition, released as Street Fighter II Dash in Japan, is a 1992 fighting game developed and published by Capcom for arcades. It is the first of several updated versions of Street Fighter II (1991), and part of the Street Fighter series. The main changes are the addition of the four grand masters as playable characters and mirror matches. The fighting techniques of the eight main characters from the original game were further balanced for competitive play.', 'https://media.retroachievements.org/Images/065742.png', 'https://media.retroachievements.org/Images/016395.png', 'https://media.retroachievements.org/Images/016381.png', 'https://media.retroachievements.org/Images/016388.png', 4.2),
  (120, 12364, 'Riot City', 'Arcade', 27, 964, 964, 964, 77, 0, 'Beat ''em Up', 'Westone', 'Sega', '1991-01-01', 'Riot City (ライオットシティ) is a 1991 2D beat ''em up arcade game developed by Westone and published by Sega.', 'https://media.retroachievements.org/Images/077526.png', 'https://media.retroachievements.org/Images/039242.png', 'https://media.retroachievements.org/Images/039240.png', 'https://media.retroachievements.org/Images/039241.png', 4.2),
  (121, 12002, 'Black Tiger', 'Arcade', 27, 954, 954, 954, 42, 0, '2D Platforming', 'Capcom', 'Capcom, Romstar', '1987-08-01', 'Black Tiger, known in Japan as Black Dragon, is a 1987 platform game developed and published by Capcom for arcades.', 'https://media.retroachievements.org/Images/072244.png', 'https://media.retroachievements.org/Images/057124.png', 'https://media.retroachievements.org/Images/057121.png', 'https://media.retroachievements.org/Images/057122.png', 4.2),
  (122, 11945, 'Donkey Kong 3', 'Arcade', 27, 941, 941, 941, 25, 0, NULL, NULL, 'Nintendo', '1983-01-01', 'Donkey Kong 3 is a 1983 shoot ''em up video game developed and published by Nintendo for arcades. It is the third installment in the Donkey Kong series, following 1982''s Donkey Kong Jr. It was ported to the Family Computer in 1984, then in North America for the Nintendo Entertainment System in 1986. The gameplay departs from previous Donkey Kong games, and it stars an exterminator named Stanley instead of Mario. The game was a modest financial success in Japan, but its commercial failure in the United States was later cited by commentators as contributing to a period of reduced activity for the series until the release of Donkey Kong (1994) and Donkey Kong Country.', 'https://media.retroachievements.org/Images/035742.png', 'https://media.retroachievements.org/Images/036712.png', 'https://media.retroachievements.org/Images/036713.png', 'https://media.retroachievements.org/Images/036714.png', 4.2),
  (123, 12751, 'DoDonPachi', 'Arcade', 27, 940, 940, 940, 53, 0, 'Shoot ''em Up, Bullet Hell', 'CAVE Interactive', 'Atlus', '1997-02-05', 'DoDonPachi is a 1997 vertically scrolling bullet hell video game developed by Cave and published by Atlus. It was the second game developed by Cave, and the sixth on Cave''s first-generation arcade hardware. As with its predecessor DonPachi, the title is both a Japanese term for expressing the sound of gunfire, and a term that relates to bees.', 'https://media.retroachievements.org/Images/057056.png', 'https://media.retroachievements.org/Images/056386.png', 'https://media.retroachievements.org/Images/057057.png', 'https://media.retroachievements.org/Images/057828.png', 4.2),
  (124, 12734, 'Super Sidekicks 2: The World Championship', 'Arcade', 27, 937, 937, 937, 23, 0, 'Sports - Football | Soccer', 'SNK', 'SNK', '1994-04-01', 'Super Sidekicks 2: The World Championship is a 1994 soccer arcade video game developed and published by SNK. It is the second installment in the Super Sidekicks series and the third soccer game released for Neo Geo MVS, preceding the original Super Sidekicks (1992). Featuring an arcade-style approach to soccer as its predecessor, the game allows players to choose any of the available game modes with AI-controlled opponents or other human players with the team of their choosing. Its gameplay uses a simplified three-button configuration.', 'https://media.retroachievements.org/Images/077485.png', 'https://media.retroachievements.org/Images/067064.png', 'https://media.retroachievements.org/Images/016673.png', 'https://media.retroachievements.org/Images/016672.png', 4.2),
  (125, 11812, 'Street Fighter Alpha 3', 'Arcade', 27, 929, 929, 929, 98, 0, '2D Fighting', 'Capcom', 'Capcom', '1998-08-01', 'Street Fighter Alpha 3, released as Street Fighter Zero 3 in Japan, Asia, South America, and Oceania, is a 1998 fighting game developed and published by Capcom for arcades. It is the third and final installment in the Street Fighter Alpha series, and runs on the same CP System II hardware as previous Alpha games. Alpha 3 further expanded the playable fighter roster from Street Fighter Alpha 2 and added new features such as selectable fighting styles called isms.', 'https://media.retroachievements.org/Images/061601.png', 'https://media.retroachievements.org/Images/016392.png', 'https://media.retroachievements.org/Images/057674.png', 'https://media.retroachievements.org/Images/057675.png', 4.2),
  (126, 12491, 'SegaSonic Cosmo Fighter Galaxy Patrol', 'Arcade', 27, 926, 926, 926, 11, 0, NULL, NULL, NULL, '1993-03-01', 'Sonic the Hedgehog is a video game series. It is published by Sega, with entries developed by Sega, Sonic Team, Traveller''s Tales, Dimps, SIMS Co., Ltd., BioWare, Hardlight, Aspect, Sumo Digital, Gameloft, Gamefam Studios, Arzest, and Rovio Entertainment. The series debuted in 1991 with the video game, Sonic the Hedgehog, released for the Mega Drive video game console. In its earliest history, most Sonic the Hedgehog games had been platform games released for Sega video game consoles and handheld game consoles (handhelds), dating from the Sega Genesis to the Sega Dreamcast. However, some of the original games were ported into versions on newer third-party home consoles and developed by various companies. As of March 2011, the series has collectively sold 89 million copies worldwide across both the platform games and spin-offs.', 'https://media.retroachievements.org/Images/108339.png', 'https://media.retroachievements.org/Images/062243.png', 'https://media.retroachievements.org/Images/062240.png', 'https://media.retroachievements.org/Images/062241.png', 4.2),
  (127, 15003, 'Tapper', 'Arcade', 27, 915, 915, 915, 15, 0, 'Action', 'Marvin Glass and Associates', 'Midway, Sega', '1984-02-01', 'Jacob Paul Tapper is an American journalist. He is the lead Washington anchor for CNN, hosts the weekday television news show The Lead with Jake Tapper, and co-hosts the Sunday morning public affairs program State of the Union.', 'https://media.retroachievements.org/Images/060809.png', 'https://media.retroachievements.org/Images/124750.png', 'https://media.retroachievements.org/Images/034266.png', 'https://media.retroachievements.org/Images/034267.png', 4.2),
  (128, 12008, 'Blade Master', 'Arcade', 27, 912, 912, 912, 56, 0, 'Beat ''em Up', 'Irem', 'Irem', '1991-01-01', 'Blade Master is a 1991 hack and slash video game developed and published by Irem for arcades. Two selectable heroes, Roy and Arnold, try to save their land from hordes of monsters. There are items to break and power-ups to collect, typical of this genre in the 1990s.', 'https://media.retroachievements.org/Images/038426.png', 'https://media.retroachievements.org/Images/037608.png', 'https://media.retroachievements.org/Images/037606.png', 'https://media.retroachievements.org/Images/037607.png', 4.2),
  (129, 15039, 'Berzerk', 'Arcade', 27, 904, 904, 904, 10, 0, NULL, 'Stern Electronics', 'Stern Electronics', '1980-11-12', 'Berzerk is a song by American rapper Eminem. The song, released on August 27, 2013, is the first single from Eminem''s eighth studio album The Marshall Mathers LP 2. The song was produced by Rick Rubin and samples Billy Squier''s The Stroke, as well as the Beastie Boys'' Fight for Your Right, taken from their 1986 debut album Licensed to Ill, which Rubin had also produced, and Naughty by Nature''s Feel Me Flow. The song was heavily downloaded in its first week of release, resulting in the song debuting at number three on the US Billboard Hot 100.', 'https://media.retroachievements.org/Images/101489.png', 'https://media.retroachievements.org/Images/093845.png', 'https://media.retroachievements.org/Images/093843.png', 'https://media.retroachievements.org/Images/093844.png', 4.2),
  (130, 12560, 'Wonder Boy', 'Arcade', 27, 903, 903, 903, 28, 0, 'Action', NULL, NULL, '1986-01-01', 'Wonder Boy is a 1986 platform game developed by Escape and published by Sega for arcades. It was later ported to the SG-1000, Master System and Game Gear video game consoles by Sega, and to the ZX Spectrum, Commodore 64 and Amstrad CPC home computers by Activision. The game is also known as Super Wonder Boy  for its Sega Mark III release in Japan and Revenge of Drancon for its Game Gear release in North America. A high definition remake of the game, titled Wonder Boy Returns, was developed by CFK and released on Steam on October 12, 2016.', 'https://media.retroachievements.org/Images/024668.png', 'https://media.retroachievements.org/Images/024667.png', 'https://media.retroachievements.org/Images/024665.png', 'https://media.retroachievements.org/Images/024666.png', 4.2),
  (131, 12774, 'Red Earth', 'Arcade', 27, 897, 897, 897, 35, 0, '2D Fighting', 'Capcom', 'Capcom', '1996-11-21', 'Red Earth, released in Japan as Warzard , is a 1996 fighting game developed and published by Capcom for arcades. It was the first game for Capcom''s CP System III hardware, the same hardware which Street Fighter III and its derivatives ran on. Red Earth received its first home console port as a part of the Capcom Fighting Collection in June 2022 for PlayStation 4, Xbox One, Nintendo Switch, and PC.', 'https://media.retroachievements.org/Images/098330.png', 'https://media.retroachievements.org/Images/065070.png', 'https://media.retroachievements.org/Images/065072.png', 'https://media.retroachievements.org/Images/065071.png', 4.2),
  (132, 12342, 'Prehistoric Isle in 1930', 'Arcade', 27, 893, 893, 893, 27, 0, 'Shoot ''em Up', 'SNK', 'SNK', '1989-05-01', 'Prehistoric Isle is a 1989 scrolling shooter arcade video game originally developed and published by SNK. Set during the 1930s, where ships at The Bahamas mysteriously disappeared, players assume the role of U.S. Marine pilots taking control of biplanes in a reconnaissance assignment at Greenhell Isle, a fictional island inhabited by dinosaurs and creatures thought to be extinct. Headed by a director under the pseudonym of Yah!, the game was developed by most of the same team that would later work on several projects for the Neo Geo platforms at SNK. First launched in arcades, the title has since been re-released through download services and compilations for various consoles. It received positive reception since its initial arcade release from critics who praised the visuals, sound design, gameplay and originality. A sequel, Prehistoric Isle 2, was released in 1999 for the Neo Geo MVS but garnered less success than its predecessor.', 'https://media.retroachievements.org/Images/035448.png', 'https://media.retroachievements.org/Images/035425.png', 'https://media.retroachievements.org/Images/035423.png', 'https://media.retroachievements.org/Images/035424.png', 4.2),
  (133, 12052, 'Cabal', 'Arcade', 27, 891, 891, 891, 34, 0, 'Gallery Shooter', 'TAD', 'Fabtek', '1988-09-01', 'A cabal is a group of people who are united in some close design, usually to promote their private views or interests in an ideology, a state, or another community, often by intrigue and usually without the knowledge of those who are outside their group. The use of this term usually carries negative connotations of political purpose, conspiracy and secrecy. It can also refer to a secret plot or a clique, or it may be used as a verb.', 'https://media.retroachievements.org/Images/036126.png', 'https://media.retroachievements.org/Images/036125.png', 'https://media.retroachievements.org/Images/036123.png', 'https://media.retroachievements.org/Images/036124.png', 4.2),
  (134, 12114, 'ESP Ra.De.', 'Arcade', 27, 891, 891, 891, 36, 0, 'Shoot ''em Up', 'CAVE Interactive', 'Atlus', '1998-04-14', 'ESP Ra.De. is a 1998 bullet hell vertically scrolling shooter originally developed by Cave as an arcade video game and co-published by Atlus and Nihon System in Japan. Set in the year 2018, players assume the role from one of the three ESPers to overthrow Lady Garra and her Yaska syndicate from taking over Tokyo.', 'https://media.retroachievements.org/Images/080597.png', 'https://media.retroachievements.org/Images/039343.png', 'https://media.retroachievements.org/Images/039341.png', 'https://media.retroachievements.org/Images/039342.png', 4.2),
  (135, 11836, 'Willow', 'Arcade', 27, 890, 890, 890, 24, 0, '2D Platforming', 'Capcom', 'Capcom', '1988-01-01', 'Willows, also called sallows and osiers, of the genus Salix, comprise around 350 species of typically deciduous trees and shrubs. They are primarily found on moist soils in cold and temperate regions.', 'https://media.retroachievements.org/Images/047625.png', 'https://media.retroachievements.org/Images/016144.png', 'https://media.retroachievements.org/Images/016145.png', 'https://media.retroachievements.org/Images/016146.png', 4.2),
  (136, 12792, 'Last Resort', 'Arcade', 27, 872, 872, 872, 23, 0, 'Shoot ''em Up', 'SNK', 'SNK', '1992-03-01', 'Last Resort is a 1992 horizontally scrolling shooter video game developed and published by SNK for the Neo Geo MVS arcade system. It was ported to the Neo Geo AES and Neo Geo CD consoles, and was later re-released as part of SNK Arcade Classics Vol. 1 for the PlayStation 2, PlayStation Portable, and Wii. In 2017, it was re-released for the Nintendo Switch, PlayStation 4, and Xbox One as part of the ACA Neo Geo series.', 'https://media.retroachievements.org/Images/033962.png', 'https://media.retroachievements.org/Images/033963.png', 'https://media.retroachievements.org/Images/022068.png', 'https://media.retroachievements.org/Images/022069.png', 4.2),
  (137, 12173, 'Gyruss', 'Arcade', 27, 867, 867, 867, 23, 0, 'Shoot ''em Up', 'Konami', 'Konami', '1983-01-01', 'Gyruss  is a 1983 tube shooter video game developed and published by Konami for Japanese arcades. It was initially licensed to Centuri in North America for dedicated machines before Konami released their own self-distributed conversion kits for the game. Parker Brothers released ports for the Atari 2600, Atari 5200, Atari 8-bit computers, ColecoVision and Commodore 64 in 1984. An enhanced version for the Famicom Disk System was released in 1988, followed by the Nintendo Entertainment System in 1989.', 'https://media.retroachievements.org/Images/035482.png', 'https://media.retroachievements.org/Images/035890.png', 'https://media.retroachievements.org/Images/035888.png', 'https://media.retroachievements.org/Images/035889.png', 4.2),
  (138, 12180, 'Hammerin'' Harry', 'Arcade', 27, 867, 867, 867, 23, 0, '2D Platforming', 'Irem', 'Irem', '1990-12-01', 'Hammerin'' Harry, known in Japan as Daiku no Gen-san , is a series of platforming video games developed and published by Irem in 1990. The titles were developed and published for the arcades, Famicom, Game Boy, Super Famicom and Sony PSP platforms. The series is centered around the titular Harry, a hammer-wielding carpenter who protects his hometown of Beranme from the corrupt construction companies that mean to tear it down.', 'https://media.retroachievements.org/Images/090490.png', 'https://media.retroachievements.org/Images/030984.png', 'https://media.retroachievements.org/Images/030982.png', 'https://media.retroachievements.org/Images/030983.png', 4.2),
  (139, 11774, 'Aero Fighters 2 (AES)', 'Arcade', 27, 865, 865, 865, 42, 0, 'Shoot ''em Up', 'Video System', 'SNK', '1994-07-18', 'Aero Fighters 2 is a 1994 vertically scrolling shooter video game developed by Video System and published by SNK for the Neo Geo MVS arcade system. It is the second installment of the Aero Fighters series, followed by the sequel Aero Fighters 3 (1995) and the spin-off Aero Fighters Assault (1997).', 'https://media.retroachievements.org/Images/117822.png', 'https://media.retroachievements.org/Images/021862.png', 'https://media.retroachievements.org/Images/021864.png', 'https://media.retroachievements.org/Images/021863.png', 4.2),
  (140, 12442, 'Superman', 'Arcade', 27, 861, 861, 861, 8, 0, 'Beat ''em Up', 'Taito', 'Taito', '1989-02-01', 'Superman is a superhero who appears in American comic books published by DC Comics. Superman was created by writer Jerry Siegel and artist Joe Shuster, and debuted in issue #1 of Action Comics, published in the United States on April 18, 1938. Superman has been regularly published in American comic books since then, and has been adapted to other media including radio serials, novels, films, television shows, theater, and video games. Superman is the archetypal superhero: he wears an outlandish costume, uses a codename, and fights evil and averts disasters with the aid of extraordinary abilities. Although there are earlier characters who arguably fit this definition, it was Superman who popularized the superhero genre and established its conventions. He was the best-selling superhero in American comic books up until the 1980s and remains the highest grossing superhero if one considers the entire history of the genre.', 'https://media.retroachievements.org/Images/055703.png', 'https://media.retroachievements.org/Images/056333.png', 'https://media.retroachievements.org/Images/021082.png', 'https://media.retroachievements.org/Images/021083.png', 4.2),
  (141, 12152, 'G.I. Joe: A Real American Hero', 'Arcade', 27, 860, 860, 860, 22, 0, 'Rail Shooter', 'Konami', 'Konami', '1992-01-01', 'G.I. Joe: A Real American Hero is a military-themed line of action figures and toys in Hasbro''s G.I. Joe franchise. The toyline lasted from 1982 to 1994, producing well over 500 figures and 250 vehicles and playsets. The line reappeared in 1997 and has continued in one form or another to the present day. It was supported by two animated series as well as a major comic series published by Marvel Comics.', 'https://media.retroachievements.org/Images/019157.png', 'https://media.retroachievements.org/Images/019156.png', 'https://media.retroachievements.org/Images/019154.png', 'https://media.retroachievements.org/Images/019613.png', 4.2),
  (142, 14880, 'Demon Front', 'Arcade', 27, 859, 859, 859, 32, 0, NULL, 'IGS', 'IGS', '2002-06-25', 'Demon Front is a side-scrolling run and gun arcade game released in 2002 by International Games System. It shares many characteristics with the Metal Slug series.', 'https://media.retroachievements.org/Images/035897.png', 'https://media.retroachievements.org/Images/035815.png', 'https://media.retroachievements.org/Images/035895.png', 'https://media.retroachievements.org/Images/035896.png', 4.2),
  (143, 11927, 'Michael Jackson''s Moonwalker', 'Arcade', 27, 855, 855, 855, 17, 0, 'Beat ''em Up', 'Sega', 'Sega', '1990-07-20', 'In 1990, several video games based on the 1988 Michael Jackson film Moonwalker, all named Michael Jackson''s Moonwalker, were released. Sega developed two beat ''em ups, one released in arcades and another released for the Sega Genesis and Master System consoles. U.S. Gold also published various games for home computers. Each of the games'' plots loosely follows the Smooth Criminal segment of the film, in which Jackson rescues kidnapped children from the evil Mr. Big, and incorporates synthesized versions of some of the musician''s songs. Following Moonwalker, Jackson collaborated with Sega on several other video games.', 'https://media.retroachievements.org/Images/049915.png', 'https://media.retroachievements.org/Images/047923.png', 'https://media.retroachievements.org/Images/047918.png', 'https://media.retroachievements.org/Images/047919.png', 4.2),
  (144, 28948, 'Muchi Muchi Pork!', 'Arcade', 27, 847, 847, 847, 28, 0, 'Shoot ''em Up, Bullet Hell', 'CAVE Interactive', 'AMI', '2007-04-26', 'Muchi Muchi Pork!  is a 2007 arcade bullet hell cute ''em up developed by CAVE, and published by AMI. It was also ported to the Xbox 360 as part of the Muchi Muchi Pork!/Pink Sweets compilation disc produced by CAVE in February 2011.', 'https://media.retroachievements.org/Images/119089.png', 'https://media.retroachievements.org/Images/092230.png', 'https://media.retroachievements.org/Images/092231.png', 'https://media.retroachievements.org/Images/092232.png', 4.2),
  (145, 12075, 'Darius', 'Arcade', 27, 843, 843, 843, 40, 0, 'Shoot ''em Up', NULL, NULL, '1987-01-01', 'Darius is a 1987 horizontally scrolling shooter video game developed and published by Taito for arcades. Players control a starship named the Silver Hawk in its mission to destroy the Belser empire before they wipe out the planet Darius. Its gameplay involves traversing through a series of scrolling levels while destroying enemies and collecting power-up icons. It is notable for its unique three-screen panoramic display.', 'https://media.retroachievements.org/Images/109230.png', 'https://media.retroachievements.org/Images/096331.png', 'https://media.retroachievements.org/Images/096329.png', 'https://media.retroachievements.org/Images/096330.png', 4.2),
  (146, 13819, 'Thrash Rally', 'Arcade', 27, 823, 823, 823, 18, 0, 'Arcade Racing', 'ADK', 'ADK', '1991-11-01', 'Thrash Rally is a racing game developed by Alpha Denshi and released by SNK for the Neo Geo system. It was released by SNK on December 20, 1991, and was followed by Over Top, a spiritual successor, in 1996.', 'https://media.retroachievements.org/Images/041575.png', 'https://media.retroachievements.org/Images/041576.png', 'https://media.retroachievements.org/Images/022336.png', 'https://media.retroachievements.org/Images/022337.png', 4.1),
  (147, 12219, 'Mighty! Pang', 'Arcade', 27, 820, 820, 820, 62, 0, 'Action', 'Mitchell', 'Mitchell, Capcom', '2000-11-01', 'Pang, originally released in Japan as Pomping World and known in North America as Buster Bros., is a 1989 action game co-produced by Mitchell Corporation and Capcom for arcades. Mitchell handled the game''s domestic and most worldwide distribution, while Capcom handled the bulk of development, and distributed the game in North American territories.', 'https://media.retroachievements.org/Images/096382.png', 'https://media.retroachievements.org/Images/024659.png', 'https://media.retroachievements.org/Images/024657.png', 'https://media.retroachievements.org/Images/024658.png', 4.1),
  (148, 18684, 'Gun Survivor 2 BIOHAZARD CODE: Veronica', 'Arcade', 27, 815, 815, 815, 41, 0, 'First-Person Shooter, Horror', 'Capcom', 'Capcom', '2001-07-01', 'Resident Evil Survivor 2 – Code: Veronica is a light gun shooter video game developed by Namco and published by Capcom as part of the Resident Evil series. The arcade version was developed in conjunction with Namco for the arcade machines. The game was released for Sega NAOMI and PlayStation 2. It was released on the PlayStation 2 on November 7, 2001, in Japan and in Europe on March 22, 2002. Whilst the PlayStation 2 release is a light gun shooter, the NAOMI arcade release features no lightgun technology whatsoever, instead deferring control of each player entirely to a three-axis joystick in the shape of a gun. The game is the second installment in the Gun Survivor series and the sequel to Resident Evil Survivor. The game is adapted from Resident Evil – Code: Veronica and features enemies and characters from that game, and enemies from Resident Evil 2 and 3. It was followed by Dino Stalker which is a spin-off of Dino Crisis, and has no ties to Resident Evil.', 'https://media.retroachievements.org/Images/071840.png', 'https://media.retroachievements.org/Images/055606.png', 'https://media.retroachievements.org/Images/054002.png', 'https://media.retroachievements.org/Images/054001.png', 4.1),
  (149, 28949, 'Akai Katana', 'Arcade', 27, 810, 810, 810, 26, 0, 'Shoot ''em Up, Bullet Hell', 'CAVE Interactive', 'CAVE Interactive', '2010-08-20', 'Akai Katana is a horizontally scrolling shooter bullet hell developed by Cave and released in Japan on August 20, 2010 for arcades. A port to the Xbox 360 with additional game modes, Akai Katana Shin, followed on May 26, 2011. Rising Star Games published the console release in North America and Europe on May 15, 2012 simply as Akai Katana.', 'https://media.retroachievements.org/Images/120905.png', 'https://media.retroachievements.org/Images/092233.png', 'https://media.retroachievements.org/Images/098914.png', 'https://media.retroachievements.org/Images/098915.png', 4.1),
  (150, 15791, 'Gunbarich', 'Arcade', 27, 806, 806, 806, 27, 0, 'Action (Ball & Paddle)', 'Psikyo', 'Psikyo', '2001-06-01', 'Psikyo  was a Japanese video game developer and publisher known for its shoot ''em ups. It was founded in 1992 by former Video System staff who worked on the Aero Fighters series. Psikyo was mainly an arcade game developer, and ported some of their games to home consoles as well.', 'https://media.retroachievements.org/Images/035753.png', 'https://media.retroachievements.org/Images/035706.png', 'https://media.retroachievements.org/Images/031595.png', 'https://media.retroachievements.org/Images/032173.png', 4.1),
  (151, 12383, 'Sly Spy', 'Arcade', 27, 790, 790, 790, 26, 0, NULL, 'Data East', 'Data East', '1989-07-01', 'Sly Spy, known in Japan as Secret Agent  and known in Europe as Sly Spy: Secret Agent, is an arcade video game developed by Data East and published in 1989. Despite not being a licensed James Bond game, Sly Spy contains references to the series.', 'https://media.retroachievements.org/Images/042389.png', 'https://media.retroachievements.org/Images/019263.png', 'https://media.retroachievements.org/Images/019260.png', 'https://media.retroachievements.org/Images/019261.png', 4.1),
  (152, 12236, 'Snow Bros.: Nick & Tom', 'Arcade', 27, 786, 786, 786, 22, 0, NULL, 'Toaplan', 'Toaplan, Romstar, Dooyong', '1990-04-01', 'Snow Bros. is a 1990 platform video game developed and published by Toaplan for Japanese arcades; it was distributed by Romstar in North America and Europe. Players control snowman twins Nick and Tom as they travel through 50 stages, using snowballs as weapons while navigating obstacles and battling monsters in order to rescue the princesses Puripuri and Puchipuchi. The game was later ported to multiple platforms, each one by different third-party developers and featuring several changes or additions. Versions for various microcomputers were in development, but were never officially released.', 'https://media.retroachievements.org/Images/021730.png', 'https://media.retroachievements.org/Images/021717.png', 'https://media.retroachievements.org/Images/021714.png', 'https://media.retroachievements.org/Images/021715.png', 4.1),
  (153, 15017, 'Night Driver', 'Arcade', 27, 781, 781, 781, 6, 0, 'Racing', 'Atari', 'Atari', '1976-10-01', 'Night Driver is a 1976 racing video game developed and published by Atari, Inc. for arcades. It is one of the earliest first-person racing video games and is commonly believed to be one of the first published video games to feature real-time first-person graphics. Night Driver has a black and white display with the hood of the player''s car painted on a plastic overlay. The road is rendered as scaled rectangles representing pylons that line the edges.', 'https://media.retroachievements.org/Images/054477.png', 'https://media.retroachievements.org/Images/054478.png', 'https://media.retroachievements.org/Images/054475.png', 'https://media.retroachievements.org/Images/054476.png', 4.1),
  (154, 11813, 'Three Wonders | Wonder 3', 'Arcade', 27, 777, 777, 777, 66, 0, 'Minigames', 'Capcom', 'Capcom', '1991-07-01', 'A one-hit wonder is a musical artist who is successful with one hit song, but without a comparable subsequent hit. The term may also be applied to an artist who is remembered for only one hit despite other successes. This article contains artists known primarily for one hit song in the United States, who are regarded as one-hit wonders by at least two sources in media even though the artist may have had multiple hits abroad.', 'https://media.retroachievements.org/Images/016271.png', 'https://media.retroachievements.org/Images/016274.png', 'https://media.retroachievements.org/Images/016272.png', 'https://media.retroachievements.org/Images/016273.png', 4.1),
  (155, 13825, 'World Heroes Perfect', 'Arcade', 27, 768, 768, 768, 74, 0, '2D Fighting', 'ADK', 'SNK', '1995-05-01', 'World Heroes Perfect is a 1995 fighting arcade game developed and published by ADK with the assistance of SNK. It was originally released for the Neo Geo MVS arcade cabinet on 25 May 1995. It is the fourth and final title of the World Heroes series.', 'https://media.retroachievements.org/Images/041287.png', 'https://media.retroachievements.org/Images/041286.png', 'https://media.retroachievements.org/Images/022358.png', 'https://media.retroachievements.org/Images/022359.png', 4.1),
  (156, 14887, 'Ketsui: Kizuna Jigoku Tachi', 'Arcade', 27, 763, 763, 763, 22, 0, 'Shoot ''em Up', 'CAVE Interactive', 'AMI', '2003-01-01', 'Ketsui: Kizuna Jigoku Tachi  is a 2003 vertical shoot ''em up arcade game by Cave, released in Japanese arcades. A Nintendo DS boss rush version was released in October 2008 in Japan. It included a Superplay DVD featuring a world record scoring run by a top ranked player. The arcade game was ported to the Xbox 360 and released in 2010. A special version of Dodonpachi Daifukkatsu Black Label was released on the Xbox 360 in 2011, which is a crossover with Ketsui, featuring the ship, re-arranged music and scoring system from Ketsui on top of the Dodonpachi Daifukkatsu Black Label scoring system.', 'https://media.retroachievements.org/Images/092900.png', 'https://media.retroachievements.org/Images/096805.png', 'https://media.retroachievements.org/Images/097943.png', 'https://media.retroachievements.org/Images/097944.png', 4.1),
  (157, 13251, 'Captain America and the Avengers', 'Arcade', 27, 747, 747, 747, 24, 0, 'Beat ''em Up', 'Data East', 'Data East', '1991-10-01', 'Captain America and the Avengers is a 1991 beat ''em up video game developed and published by Data East for arcades. It features the Avengers team of Marvel Comics characters in a side-scrolling brawling and shooting adventure to defeat the evil Red Skull. The game received ports for the Sega Genesis/Mega Drive, Super Nintendo Entertainment System, Game Boy and Game Gear. A different Data East game was released for the Nintendo Entertainment System.', 'https://media.retroachievements.org/Images/104980.png', 'https://media.retroachievements.org/Images/019184.png', 'https://media.retroachievements.org/Images/019182.png', 'https://media.retroachievements.org/Images/019183.png', 4.1),
  (158, 13761, 'Breaker''s', 'Arcade', 27, 739, 739, 739, 33, 0, '2D Fighting', 'Visco', 'Visco', '1996-03-01', 'Breakout is a 1976 action video game developed and published by Atari, Inc. for arcades; in Japan, it was released by Namco. The game was designed by Nolan Bushnell and Steve Bristow and prototyped via discrete logic chips by Steve Wozniak with assistance from Steve Jobs. In the game, eight rows of bricks line the top portion of the screen, and the player''s goal is to destroy the bricks by repeatedly bouncing a ball off a paddle into them. The concept was predated by Ramtek''s Clean Sweep (1974), but the game''s designers were influenced by Atari''s own Pong (1972). The arcade version of Breakout uses a monochrome display underneath a translucent colored overlay.', 'https://media.retroachievements.org/Images/119920.png', 'https://media.retroachievements.org/Images/027996.png', 'https://media.retroachievements.org/Images/021947.png', 'https://media.retroachievements.org/Images/021948.png', 4.1),
  (159, 13811, 'Soccer Brawl', 'Arcade', 27, 735, 735, 735, 30, 0, 'Sports (Football / Soccer)', 'SNK', 'SNK', '1992-02-01', 'Brawl Stars is a multiplayer online battle arena and hero shooter video game developed and published by Finnish video game company Supercell. The game was released worldwide on 12 December 2018, on iOS and Android platforms. The game features a variety of game modes, each with a distinctive objective. Players are able to choose from a large selection of unlockable characters, called Brawlers, who each have different abilities and playstyles.', 'https://media.retroachievements.org/Images/032846.png', 'https://media.retroachievements.org/Images/032845.png', 'https://media.retroachievements.org/Images/022278.png', 'https://media.retroachievements.org/Images/022279.png', 4.1),
  (160, 11985, 'Alien Storm', 'Arcade', 27, 731, 731, 731, 22, 0, NULL, 'Sega', 'Sega', '1990-04-25', 'Alien Storm (エイリアンストーム) is a beat ''em up shooter released as an arcade video game by Sega in 1990. It was ported to the Genesis/Mega Drive and Master System. The Mega Drive version was re-released on Wii''s Virtual Console in 2007 and was also included on Sonic''s Ultimate Genesis Collection for Xbox 360 and PlayStation 3. The game was also re-released on the Nintendo Classics service in 2022.', 'https://media.retroachievements.org/Images/123055.png', 'https://media.retroachievements.org/Images/096267.png', 'https://media.retroachievements.org/Images/096268.png', 'https://media.retroachievements.org/Images/096269.png', 4.1),
  (161, 11941, 'Dyna Gear', 'Arcade', 27, 724, 724, 724, 17, 0, 'Run & Gun', 'Scarab', 'Sammy', '1994-01-01', 'Bomberman, also known as Dyna Blaster in Europe, is a 1990 action maze video game developed and published by Hudson Soft for the TurboGrafx-16. An entry in the Bomberman franchise, it is a reimagining of the first game in the series. The game was later ported to home computers, each one featuring changes compared to the original version. Conversions for other platforms were in development but never released. The game garnered positive reception from critics since its initial release on the TurboGrafx-16 and later on home computers.', 'https://media.retroachievements.org/Images/063423.png', 'https://media.retroachievements.org/Images/063422.png', 'https://media.retroachievements.org/Images/063421.png', 'https://media.retroachievements.org/Images/063420.png', 4.1),
  (162, 11955, 'Strider', 'Arcade', 27, 715, 715, 715, 22, 0, NULL, 'Capcom', 'Capcom', '1989-01-01', 'Strider, released in Japan as Strider Hiryū, is a 1989 hack and slash platform game developed and published by Capcom for arcades. Set in a dystopian future where Earth is ruled by the tyrannical Grandmaster Meio, it follows the titular Strider named Hiryu as he attempts to end his tyrannical reign for good. The game resulted from cooperation between Capcom and manga publisher Moto Kikaku. It marked the video game debut of Strider Hiryu, after the character was introduced in the 1988 manga Strider Hiryu.', 'https://media.retroachievements.org/Images/065284.png', 'https://media.retroachievements.org/Images/028716.png', 'https://media.retroachievements.org/Images/067695.png', 'https://media.retroachievements.org/Images/067696.png', 4.1),
  (163, 13859, 'Espgaluda', 'Arcade', 27, 711, 711, 711, 27, 0, 'Shoot ''em Up, Bullet Hell', 'CAVE Interactive', 'AMI', '2003-10-15', 'Espgaluda II (エスプガルーダII) is a bullet hell shoot''em up originally released by Cave in the arcades in 2005 as a sequel to Espgaluda. An Xbox 360 release, titled Espgaluda II Black Label, was released in 2010 in Japan. It was released in September 2021 for the Nintendo Switch worldwide.', 'https://media.retroachievements.org/Images/081244.png', 'https://media.retroachievements.org/Images/093956.png', 'https://media.retroachievements.org/Images/081256.png', 'https://media.retroachievements.org/Images/081255.png', 4.1),
  (164, 13853, 'Sengoku Blade: Sengoku Ace Episode II', 'Arcade', 27, 708, 708, 708, 59, 0, 'Shoot ''em Up', 'Psikyo', 'Psikyo', '1996-04-01', 'Tengai, known as Sengoku Blade in Japan, is a horizontally scrolling shoot ''em up video game released for arcade machines in 1996 by Psikyo as a sequel to their 1993 shooter Sengoku Ace. A home console version was also released for the Sega Saturn. The game was ported years later to the PlayStation 2, and again for iOS and Android devices and the Nintendo Switch, Windows, PlayStation 4 and Xbox One. The game is set in a historical fantasy version of the Sengoku period of Japanese history, featuring demons, magic and steam-powered robotics.', 'https://media.retroachievements.org/Images/062938.png', 'https://media.retroachievements.org/Images/062889.png', 'https://media.retroachievements.org/Images/022498.png', 'https://media.retroachievements.org/Images/022499.png', 4.1),
  (165, 12533, 'Twinkle Star Sprites', 'Arcade', 27, 701, 701, 701, 34, 0, 'Shoot ''em Up', 'ADK', 'SNK', '1996-11-25', 'Twinkle Star Sprites is a 1996 scrolling shooter arcade game developed by ADK and published by SNK. It was ADK''s last production for the Neo Geo. Two players are each in separate, side-by-side, vertically scrolling levels. Combinations of shots and timed power-ups damage the other player. These attacks also serve as counters to the opponent''s attack.', 'https://media.retroachievements.org/Images/115711.png', 'https://media.retroachievements.org/Images/062789.png', 'https://media.retroachievements.org/Images/022343.png', 'https://media.retroachievements.org/Images/022344.png', 4.1),
  (166, 11804, 'Vendetta', 'Arcade', 27, 682, 682, 682, 41, 0, 'Beat ''em Up', 'Konami', 'Konami', '1991-01-01', 'Vendetta, known in Japan as Crime Fighters 2, is a 1991 beat ''em up video game developed and published by Konami for arcades. It was released in Japan in July 1991 and in North America in September 1991. It is a sequel to Konami''s 1989 game Crime Fighters, although it was marketed internationally as a stand-alone game with no previous connections. Hamster Corporation released the game as part of their Arcade Archives series for the Nintendo Switch and PlayStation 4 in July 2021.', 'https://media.retroachievements.org/Images/066678.png', 'https://media.retroachievements.org/Images/066040.png', 'https://media.retroachievements.org/Images/066041.png', 'https://media.retroachievements.org/Images/066042.png', 4.1),
  (167, 12255, 'Street Fighter II Turbo: Hyper Fighting', 'Arcade', 27, 680, 680, 680, 26, 0, '2D Fighting', 'Capcom', 'Capcom', '1992-12-01', 'Street Fighter II Turbo: Hyper Fighting, released as Street Fighter II Dash Turbo in Japan, is a 1992 fighting game developed and published by Capcom for arcades. It is the third arcade version of Street Fighter II, part of the Street Fighter franchise, following Street Fighter II: Champion Edition, and was initially released as an enhancement kit for that game. Released less than a year after the previous installment, Hyper Fighting introduced a faster playing speed and new special moves for certain characters, as well as further refinement to the character balance.', 'https://media.retroachievements.org/Images/116918.png', 'https://media.retroachievements.org/Images/016396.png', 'https://media.retroachievements.org/Images/016382.png', 'https://media.retroachievements.org/Images/016389.png', 4.1),
  (168, 13758, 'Andro Dunos', 'Arcade', 27, 671, 671, 671, 32, 0, 'Shoot ''em Up', 'Visco', 'Visco', '1992-06-15', 'Andro Dunos is a scrolling shooter arcade video game developed by Visco Corporation and originally published by SNK on June 15, 1992. It is the first title to be created by Visco for both the Neo Geo MVS (arcade) and Neo Geo AES (home) platforms. Andro Dunos, along with 1996''s Breakers are the only two Visco developed games to be officially licensed for distribution on the Neo Geo AES platform. All other Visco games were only released on the Neo Geo MVS arcade platform.', 'https://media.retroachievements.org/Images/099452.png', 'https://media.retroachievements.org/Images/088058.png', 'https://media.retroachievements.org/Images/021932.png', 'https://media.retroachievements.org/Images/021933.png', 4.1),
  (169, 15882, 'Tetris: The Absolute - The Grand Master 2 Plus', 'Arcade', 27, 670, 670, 670, 84, 0, NULL, 'Arika', 'Arika', '2001-01-01', 'Tetris: The Grand Master  is a series of puzzle arcade video games created by Arika.', 'https://media.retroachievements.org/Images/080117.png', 'https://media.retroachievements.org/Images/044302.png', 'https://media.retroachievements.org/Images/031749.png', 'https://media.retroachievements.org/Images/031753.png', 4.1),
  (170, 12343, 'Prehistoric Isle 2', 'Arcade', 27, 668, 668, 668, 27, 0, 'Shoot ''em Up', 'Yumekobo', 'Yumekobo', '1999-09-27', 'Prehistoric Isle 2 is a 1999 scrolling shooter arcade video game co-developed by Saurus and Yumekobo and published by SNK. It is the sequel to the original Prehistoric Isle, which was developed and released earlier in 1989 by SNK. In the game, players take control of helicopters to shoot at dinosaurs while rescuing people. Although first launched in arcades, the title has since been re-released through download services for various consoles. It received mixed reception since its initial arcade release and garnered less success than its predecessor.', 'https://media.retroachievements.org/Images/097733.png', 'https://media.retroachievements.org/Images/088191.png', 'https://media.retroachievements.org/Images/022231.png', 'https://media.retroachievements.org/Images/022230.png', 4.1),
  (171, 17496, 'Jurassic Park', 'Arcade', 27, 666, 666, 666, 9, 0, NULL, 'Sega', 'Sega', '1994-02-01', 'Jurassic Park is a 1993 American science fiction film directed by Steven Spielberg and written by Michael Crichton and David Koepp, based on Crichton''s 1990 novel. Starring Sam Neill, Laura Dern, Jeff Goldblum, Richard Attenborough, Bob Peck, Martin Ferrero, BD Wong, Samuel L. Jackson, Wayne Knight, Joseph Mazzello, and Ariana Richards, the film is set on the fictional island of Isla Nublar near Costa Rica, where wealthy businessman John Hammond (Attenborough) and a team of genetic scientists have created a wildlife park of de-extinct dinosaurs. When industrial sabotage leads to a catastrophic shutdown of the park''s power facilities and security precautions, a small group of visitors struggle to survive and escape the now perilous island.', 'https://media.retroachievements.org/Images/093193.png', 'https://media.retroachievements.org/Images/042568.png', 'https://media.retroachievements.org/Images/042569.png', 'https://media.retroachievements.org/Images/042570.png', 4.1),
  (172, 15758, 'Crazy Kong', 'Arcade', 27, 664, 664, 664, 42, 0, '2D Platforming, Arcade', 'Falcon', 'Falcon', '1981-01-01', 'Crazy Kong  is an arcade video game developed by Falcon, released in 1981 and similar to Nintendo''s Donkey Kong. Although commonly believed to be a bootleg version, it was officially licensed for operation only in Japan when Nintendo could not keep up with domestic demand, and is based on different hardware. It retains all the gameplay elements of Donkey Kong, but its graphics were redrawn and re-colorized. Falcon breached their contract by exporting the cabinets overseas, leading Nintendo to revoke the license in January 1982. Like the original game, Crazy Kong had bootleg versions under such titles as Congorilla, Big Kong, Donkey King and Monkey Donkey.', 'https://media.retroachievements.org/Images/122437.png', 'https://media.retroachievements.org/Images/068205.png', 'https://media.retroachievements.org/Images/068579.png', 'https://media.retroachievements.org/Images/068580.png', 4.1),
  (173, 11949, 'Punch-Out!!', 'Arcade', 27, 664, 664, 664, 22, 0, 'Sports - Boxing', 'Nintendo', 'Nintendo', '1984-02-17', 'Super Punch-Out!! is a boxing video game developed and published by Nintendo for the Super Nintendo Entertainment System (SNES). It was released on October 24, 1994 in North America and again in the same region in 1996. It was released in the United Kingdom on February 10, 1995 for the same console and in Japan in 1998 for the Super Famicom through the Nintendo Power flash RAM cartridge series. The game is also included in the GameCube version of Fight Night Round 2 as an extra game due to the inclusion of Little Mac in the game. The game was released for the Wii''s Virtual Console in Europe on March 20, 2009, in North America on March 30, 2009, and in Japan on July 7, 2009. The game was also released on the New Nintendo 3DS eShop on May 5, 2016. Nintendo re-released Super Punch-Out!! in the United States in September 2017 as part of the company''s Super NES Classic Edition. It is the fourth game in the Punch-Out!! series, taking place after the Punch-Out!! game for the Nintendo Entertainment System (NES).', 'https://media.retroachievements.org/Images/121548.png', 'https://media.retroachievements.org/Images/124357.png', 'https://media.retroachievements.org/Images/019349.png', 'https://media.retroachievements.org/Images/060835.png', 4.1),
  (174, 11754, 'The King of Fighters 2003', 'Arcade', 27, 662, 662, 662, 58, 0, '2D Fighting', 'SNK', 'SNK', '2003-03-11', 'The King of Fighters 2003 (KOF 2003, or KOF ''03) is a 2003 fighting video game developed and published by SNK Playmore for the Neo Geo arcade and home platforms. It is the tenth game in The King of Fighters series, and the last entry released for the Neo Geo, which had served as the primary platform for the series since The King of Fighters ''94. It was ported to the PlayStation 2 and Xbox, and was released on both consoles in North America in a two-in-one bundle with the preceding game in the series, The King of Fighters 2002. Character designs and artwork were handled by artist Falcoon.', 'https://media.retroachievements.org/Images/109162.png', 'https://media.retroachievements.org/Images/016473.png', 'https://media.retroachievements.org/Images/016465.png', 'https://media.retroachievements.org/Images/016468.png', 4.1),
  (175, 11798, 'Street Fighter Alpha 2', 'Arcade', 27, 641, 641, 641, 49, 0, '2D Fighting', 'Capcom', 'Capcom', '1996-01-01', 'Street Fighter Alpha 2, known as Street Fighter Zero 2 in Japan, Asia, South America, and Oceania, is a 1996 fighting game developed and published by Capcom for arcades. The game is the sequel to the previous year''s Street Fighter Alpha: Warriors'' Dreams and features a number of improvements, such as new attacks, stages, endings, and gameplay features. It was ported to the PlayStation, Sega Saturn and Super Nintendo home consoles globally in 1996, and later a Windows port. It was followed by Street Fighter Alpha 3 in 1998.', 'https://media.retroachievements.org/Images/050132.png', 'https://media.retroachievements.org/Images/016393.png', 'https://media.retroachievements.org/Images/016380.png', 'https://media.retroachievements.org/Images/016385.png', 4.1),
  (176, 12481, 'Pac-Mania', 'Arcade', 27, 634, 634, 634, 35, 0, 'Maze Chase', 'Namco', NULL, '1987-12-01', 'Pac-Mania is a 1987 maze video game developed and published by Namco for Japanese arcades; it was licensed to Atari Games for release in North America. In the game, the player controls Pac-Man as he must eat all of the dots while avoiding the colored ghosts that chase him in the maze. Eating large flashing Power Pellets will allow Pac-Man to eat the ghosts for bonus points, which lasts for a short period of time. A new feature to this game allows Pac-Man to jump over the ghosts to evade capture. It is the ninth title in the Pac-Man video game series and was the last one developed for arcades up until the release of Pac-Man Arrangement in 1996. Development was directed by Pac-Man creator Tōru Iwatani.', 'https://media.retroachievements.org/Images/092335.png', 'https://media.retroachievements.org/Images/088580.png', 'https://media.retroachievements.org/Images/088487.png', 'https://media.retroachievements.org/Images/088488.png', 4.1),
  (177, 12040, 'The Last Blade', 'Arcade', 27, 629, 629, 629, 66, 0, '2D Fighting', 'SNK', 'SNK', '1997-12-05', 'The Last Blade is a fighting game developed and released by SNK for the Neo Geo system in 1997. It was also ported to several home systems. A sequel, The Last Blade 2, was released in 1998. A second sequel, The Last Blade: Beyond the Destiny, was released in 2000.', 'https://media.retroachievements.org/Images/122040.png', 'https://media.retroachievements.org/Images/040223.png', 'https://media.retroachievements.org/Images/022064.png', 'https://media.retroachievements.org/Images/040328.png', 4.1),
  (178, 12310, 'Mr. Do!', 'Arcade', 27, 628, 628, 628, 22, 0, 'Maze Chase', 'Universal', 'Universal', '1982-01-01', 'Mr. Do! is a 1982 maze video game developed by Universal. It is the first arcade video game to be released as a conversion kit for other cabinets; Taito published the conversion kit in Japan. The game was inspired by Namco''s Dig Dug, released earlier in 1982. Mr. Do! was a commercial success in Japan and North America, selling 30,000 arcade units in the US, and it was followed by several arcade sequels.', 'https://media.retroachievements.org/Images/124334.png', 'https://media.retroachievements.org/Images/039624.png', 'https://media.retroachievements.org/Images/039623.png', 'https://media.retroachievements.org/Images/039625.png', 4.1),
  (179, 12766, 'Aero Fighters 3', 'Arcade', 27, 625, 625, 625, 46, 0, 'Shoot ''em Up', 'Video System', 'SNK', '1995-10-12', 'Aero Fighters 3 is a 1995 vertically scrolling shooter video game developed and published by Video System for the Neo Geo MVS arcade system in Japan; it was distributed by SNK in North America and Europe. It was later ported to the Neo Geo AES and Neo Geo CD home consoles; the Neo Geo AES version was not released in North America. The game was later re-released for PlayStation 4, Xbox One, and Nintendo Switch in 2018 by the eventual copyright holder for the game, Hamster Corporation.', 'https://media.retroachievements.org/Images/120531.png', 'https://media.retroachievements.org/Images/088053.png', 'https://media.retroachievements.org/Images/021926.png', 'https://media.retroachievements.org/Images/021927.png', 4.1),
  (180, 11829, 'Mars Matrix: Hyper Solid Shooting', 'Arcade', 27, 625, 625, 625, 29, 0, 'Shoot ''em Up', 'Takumi', NULL, '2000-06-01', 'Mars Matrix: Hyper Solid Shooting, or simply Mars Matrix , is a 2000 vertically scrolling shooter arcade game developed by Takumi, published by Capcom, and run on their CPS-2 arcade system board. Mars Matrix was later ported to the Dreamcast video game console in 2001. The arcade version uses a horizontally aligned monitor, despite being a vertically scrolling game.', 'https://media.retroachievements.org/Images/083152.png', 'https://media.retroachievements.org/Images/017015.png', 'https://media.retroachievements.org/Images/017011.png', 'https://media.retroachievements.org/Images/017013.png', 4.1),
  (181, 28669, 'Deathsmiles: Mega Black Label', 'Arcade', 27, 624, 624, 624, 61, 0, 'Shoot ''em Up, Bullet Hell', 'CAVE Interactive', 'AMI', '2008-10-06', 'Deathsmiles  is a horizontally scrolling shooter arcade video game by Japanese developer Cave, released in late 2007. It has heavy occult and gothic influences. It is the second Cave shooter to be played using a horizontally-oriented monitor. It was the first Cave shooter released in North America on a console, and the first one in Europe. Cave has also released it for iOS. A sequel, Deathsmiles II, was released to Japanese arcades on May 14, 2009. A compilation of both Deathsmiles I and Deathsmiles II was released for PlayStation 4, Xbox One and Nintendo Switch in Japan on December 16, 2021.', 'https://media.retroachievements.org/Images/094642.png', 'https://media.retroachievements.org/Images/091985.png', 'https://media.retroachievements.org/Images/094643.png', 'https://media.retroachievements.org/Images/094644.png', 4.1),
  (182, 13567, 'Pachinko Sexy Reaction 2', 'Arcade', 27, 603, 603, 603, 10, 0, 'Casino, Pachinko', 'Sammy', 'Sammy', '1999-01-01', 'The Sega Saturn is a 32-bit fifth-generation home video game console that was developed by Sega and first released on November 22, 1994. Its games are in CD-ROM format, and its game library contains several arcade ports as well as original titles. There are 1028 games on this list not including non-game software and compilations of Saturn games. 775 of those games were released as Japan-only exclusives, which makes up 75% of the list. For games that were announced or in development for the Saturn, but never released, see the list of cancelled Sega Saturn games.', 'https://media.retroachievements.org/Images/034174.png', 'https://media.retroachievements.org/Images/051324.png', 'https://media.retroachievements.org/Images/021171.png', 'https://media.retroachievements.org/Images/034147.png', 4),
  (183, 13384, 'Zombie Raid', 'Arcade', 27, 603, 603, 603, 23, 0, 'Rail Shooter', 'Sammy', 'Sammy', '1995-01-01', 'Zombie Raid is a screen scrolling, horror-themed light gun shooter game released for the arcade by American Sammy in January 1995.', 'https://media.retroachievements.org/Images/106437.png', 'https://media.retroachievements.org/Images/019659.png', 'https://media.retroachievements.org/Images/106438.png', 'https://media.retroachievements.org/Images/106439.png', 4),
  (184, 22131, 'DoDonPachi DaiFukkatsu Black Label', 'Arcade', 27, 599, 599, 599, 60, 0, 'Bullet Hell, Shoot ''em Up', 'CAVE Interactive', 'DEGICA', '2010-01-20', 'DoDonPachi Resurrection, known in Japan as DoDonPachi DaiFukkatsu , is the fifth arcade game in Cave''s DonPachi series, published in 2008. The game was unveiled at AOU2008 Amusement EXPO.', 'https://media.retroachievements.org/Images/110860.png', 'https://media.retroachievements.org/Images/110861.png', 'https://media.retroachievements.org/Images/066687.png', 'https://media.retroachievements.org/Images/110859.png', 4),
  (185, 11948, 'Arm Wrestling', 'Arcade', 27, 598, 598, 598, 15, 0, 'Action', 'Nintendo', 'Nintendo', '1985-05-01', 'Arm wrestling is a strength sport in which two participants, facing each other with their bent elbows placed on a flat surface and hands firmly gripped, each attempt to pin their opponent''s hand by forcing it to the surface. In popular culture, arm wrestling is commonly interpreted as a display of physical dominance, symbolizing superior strength and toughness between two individuals.', 'https://media.retroachievements.org/Images/050156.png', 'https://media.retroachievements.org/Images/036382.png', 'https://media.retroachievements.org/Images/019348.png', 'https://media.retroachievements.org/Images/036383.png', 4),
  (186, 15009, 'Asteroids', 'Arcade', 27, 596, 596, 596, 12, 0, NULL, 'Atari', 'Atari', '1979-11-01', 'An asteroid is a minor planet—an object larger than a meteoroid that is neither a planet nor an identified comet—that orbits within the inner Solar System or is co-orbital with Jupiter. Asteroids are rocky, metallic, or icy bodies with no atmosphere, and are broadly classified into C-type (carbonaceous), M-type (metallic), or S-type (silicaceous). The size and shape of asteroids vary significantly, ranging from small rubble piles under a kilometer across to Ceres, a dwarf planet almost 1000 km in diameter. A body is classified as a comet, not an asteroid, if it shows a coma (tail) when warmed by solar radiation, although recent observations suggest a continuum between these types of bodies.', 'https://media.retroachievements.org/Images/108929.png', 'https://media.retroachievements.org/Images/033985.png', 'https://media.retroachievements.org/Images/033986.png', 'https://media.retroachievements.org/Images/033987.png', 4),
  (187, 11860, 'Windjammers', 'Arcade', 27, 591, 591, 591, 18, 0, 'Sports (Flying Disc)', 'Data East', 'Data East', '1994-02-17', 'Windjammers is a sports arcade game released by Data East on the Neo Geo arcade system in 1994. The game mechanics are essentially the same as Pong or air hockey, where players continuously shoot a flying disc at the goal zone of the opponent attempting to score. The game can be played against the computer or in a 2 player versus. Dotemu ported the game to PlayStation 4 and PlayStation Vita in August 2017, Nintendo Switch in October 2018, and iiRcade in February 2021. Dotemu would later develop and publish a sequel, Windjammers 2, which was released on PlayStation 4, Xbox One, Nintendo Switch, PC and Google Stadia on January 20, 2022.', 'https://media.retroachievements.org/Images/078318.png', 'https://media.retroachievements.org/Images/029797.png', 'https://media.retroachievements.org/Images/020837.png', 'https://media.retroachievements.org/Images/020838.png', 4),
  (188, 18013, 'Alien 3: The Gun', 'Arcade', 27, 588, 588, 588, 15, 0, NULL, 'Sega', 'Sega', '1993-09-01', 'Alien 3: The Gun is a 1993 rail shooter arcade video game released by Sega. It is based on the film Alien 3, but focuses on two space Marines.', 'https://media.retroachievements.org/Images/096321.png', 'https://media.retroachievements.org/Images/049078.png', 'https://media.retroachievements.org/Images/049076.png', 'https://media.retroachievements.org/Images/049077.png', 4),
  (189, 12242, 'Super Puzzle Fighter II Turbo', 'Arcade', 27, 585, 585, 585, 39, 0, NULL, 'Capcom', 'Capcom', '1996-05-31', 'Super Puzzle Fighter II Turbo, released in Japan as Super Puzzle Fighter II X, is a 1996 tile-matching puzzle video game developed and published by Capcom for arcades. The game''s title is a play on Super Street Fighter II Turbo, as there were no other Puzzle Fighter games at the time, and the game includes music and interface elements spoofing the Street Fighter Alpha and Darkstalkers games. It was a response to Compile and Sega''s Puyo Puyo 2 that had been sweeping the Japanese arcade scene.', 'https://media.retroachievements.org/Images/019678.png', 'https://media.retroachievements.org/Images/078676.png', 'https://media.retroachievements.org/Images/078674.png', 'https://media.retroachievements.org/Images/078675.png', 4),
  (190, 13799, 'Ninja Master''s: Haou Ninou Chou', 'Arcade', 27, 583, 583, 583, 60, 0, '2D Fighting', 'ADK, Hamster', 'SNK', '1996-05-26', NULL, 'https://media.retroachievements.org/Images/040209.png', 'https://media.retroachievements.org/Images/040199.png', 'https://media.retroachievements.org/Images/022160.png', 'https://media.retroachievements.org/Images/022161.png', 4),
  (191, 11870, 'Cotton: Fantastic Night Dreams', 'Arcade', 27, 580, 580, 580, 28, 0, 'Shoot ''em Up', 'Success', 'Sega', '1991-03-01', 'Cotton: Fantastic Night Dreams is a 1991 scrolling shooter video game developed by Success and published by Sega for Japanese arcades. The first installment in the Cotton series, players assume the role of the young witch Cotton who, alongside her fairy companion Silk, sets out on her broomstick on a quest to defeat several monsters and get her Willow candy. Its gameplay mainly consists of shooting mixed with role-playing elements using a main two-button configuration. It ran on the Sega System 16 hardware.', 'https://media.retroachievements.org/Images/059015.png', 'https://media.retroachievements.org/Images/019248.png', 'https://media.retroachievements.org/Images/019244.png', 'https://media.retroachievements.org/Images/019245.png', 4),
  (192, 12724, 'Real Bout Fatal Fury', 'Arcade', 27, 580, 580, 580, 54, 0, '2D Fighting', 'SNK', 'SNK', '1995-12-21', 'Real Bout Fatal Fury is a 1995 fighting game developed and published by SNK for the Neo Geo arcade and home platforms. It is the fourth mainline installment in the Fatal Fury series, following Fatal Fury 3: Road to the Final Victory, and the first game of the Real Bout sub-series.', 'https://media.retroachievements.org/Images/114366.png', 'https://media.retroachievements.org/Images/065100.png', 'https://media.retroachievements.org/Images/016607.png', 'https://media.retroachievements.org/Images/066770.png', 4),
  (193, 12452, 'Alien Sector', 'Arcade', 27, 564, 564, 564, 21, 0, 'Shoot ''em Up', 'Namco', 'Namco', '1985-05-25', 'Baraduke, renamed Alien Sector in some regions, is a run and gun video game released for arcades by Namco in 1985. A home version was published for the X68000 in 1995.', 'https://media.retroachievements.org/Images/095397.png', 'https://media.retroachievements.org/Images/095396.png', 'https://media.retroachievements.org/Images/019330.png', 'https://media.retroachievements.org/Images/095395.png', 4),
  (194, 12214, 'Knights of the Round', 'Arcade', 27, 557, 557, 557, 57, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1991-11-27', 'Knights of the Round is a 1991 beat ''em up game developed and published by Capcom for arcades. Based loosely on the legend of King Arthur and the Knights of the Round Table, the game features an action role-playing-like level advancement system, with fighters automatically being upgraded to new weapons and armor as they advance through the game. The arcade version of the game was included in the compilations Capcom Beat ''Em Up Bundle (2018) and Capcom Arcade 2nd Stadium (2022).', 'https://media.retroachievements.org/Images/101834.png', 'https://media.retroachievements.org/Images/022809.png', 'https://media.retroachievements.org/Images/022807.png', 'https://media.retroachievements.org/Images/022810.png', 4),
  (195, 12860, 'Raiden II', 'Arcade', 27, 549, 549, 549, 41, 0, 'Shoot ''em Up', 'Seibu Kaihatsu', 'Fabtek', '1993-11-01', 'Raiden II  is a 1993 vertically scrolling shooter arcade video game developed and published by Seibu Kaihatsu. It is the second game in the Raiden series which started with Raiden in 1990.', 'https://media.retroachievements.org/Images/096843.png', 'https://media.retroachievements.org/Images/096457.png', 'https://media.retroachievements.org/Images/030208.png', 'https://media.retroachievements.org/Images/030209.png', 4),
  (196, 12067, 'Crime City', 'Arcade', 27, 540, 540, 540, 18, 0, NULL, 'Taito', 'Taito', '1989-09-01', 'True Crime: New York City is a 2005 action-adventure video game developed by Luxoflux for PlayStation 2. It was ported to GameCube and Xbox by Exakt Entertainment, to Microsoft Windows by Aspyr, and to mobile by Hands-On Mobile. It was published on all systems by Activision. The PlayStation 2, Xbox and GameCube versions were released in November 2005, the PC version in March 2006, and the mobile version in March 2007. It is the second and final entry in the True Crime franchise, after the 2003 game, True Crime: Streets of LA.', 'https://media.retroachievements.org/Images/079303.png', 'https://media.retroachievements.org/Images/019259.png', 'https://media.retroachievements.org/Images/019256.png', 'https://media.retroachievements.org/Images/019257.png', 4),
  (197, 11944, 'Donkey Kong Junior', 'Arcade', 27, 533, 533, 533, 22, 0, '2D Platforming, Arcade', 'Nintendo', 'Nintendo', '1982-08-01', 'Donkey Kong Jr. is a 1982 platform game developed and published by Nintendo for arcades. It is the sequel to 1981''s Donkey Kong, but with the roles reversed compared to its predecessor: Mario is now the villain and Donkey Kong Jr. is trying to save his kidnapped father. After its initial release in arcades, the game was ported to a variety of home consoles, including the Famicom/Nintendo Entertainment System. The game''s title is written as Donkey Kong Junior in the North American arcade version and various conversions to non-Nintendo systems.', 'https://media.retroachievements.org/Images/035728.png', 'https://media.retroachievements.org/Images/115860.png', 'https://media.retroachievements.org/Images/036409.png', 'https://media.retroachievements.org/Images/036410.png', 4),
  (198, 11896, 'Pooyan', 'Arcade', 27, 524, 524, 524, 23, 0, 'Shoot ''em Up', 'Konami', 'Konami', '1982-01-01', 'Pooyan is a 1982 fixed shooter video game developed and published by Konami for arcades. It was released in North America by Stern Electronics. The player controls Mama, a pig whose babies have been kidnapped by a group of wolves. It was later ported to home consoles and personal computers.', 'https://media.retroachievements.org/Images/035603.png', 'https://media.retroachievements.org/Images/037783.png', 'https://media.retroachievements.org/Images/037780.png', 'https://media.retroachievements.org/Images/037781.png', 4),
  (199, 15020, 'Defender', 'Arcade', 27, 519, 519, 519, 37, 0, 'Shoot ''em Up', 'Williams Entertainment', 'Williams Entertainment', '1981-02-01', 'An arcade video game is an arcade game that takes player input from its controls, processes it through electrical or computerized components, and displays output to an electronic monitor or similar display. All arcade video games are coin-operated or accept other means of payment, housed in an arcade cabinet, and located in amusement arcades alongside other kinds of arcade games. Until the early 2000s, arcade video games were the largest and most technologically advanced segment of the video game industry.', 'https://media.retroachievements.org/Images/070479.png', 'https://media.retroachievements.org/Images/071807.png', 'https://media.retroachievements.org/Images/070477.png', 'https://media.retroachievements.org/Images/070478.png', 4),
  (200, 12359, 'Rambo III', 'Arcade', 27, 519, 519, 519, 8, 0, 'Rail Shooter', 'Taito', 'Taito', '1989-01-01', 'Rambo III is a 1988 American war action film starring Sylvester Stallone as Vietnam War veteran John Rambo. Directed by Peter MacDonald, the script was co-written by Stallone and Sheldon Lettich. It is a sequel to Rambo: First Blood Part II (1985) and the third installment in the Rambo film series. Richard Crenna reprises his role as Colonel Sam Trautman.', 'https://media.retroachievements.org/Images/059522.png', 'https://media.retroachievements.org/Images/058858.png', 'https://media.retroachievements.org/Images/021013.png', 'https://media.retroachievements.org/Images/021014.png', 4);
